import React, { useState, useEffect, useRef } from 'react'
import { Routes, Route, useNavigate, useParams } from 'react-router-dom'
import Sidebar from './components/Sidebar'
import StageScript from './components/StageScript'
import StageAssets from './components/StageAssets'
import StageDirector from './components/StageDirector'
import StageExport from './components/StageExport'
import StagePrompts from './components/StagePrompts'
import LarkDirector from './components/LarkDirector'
import AccountCenter from './components/account-center'
import Dashboard from './components/Dashboard'
import ProjectOverview from './components/ProjectOverview'
import CharacterLibraryPage from './components/CharacterLibrary'
import NewApiConsole from './components/NewApiConsole'
import Onboarding, {
  shouldShowOnboarding,
  resetOnboarding
} from './components/Onboarding'
import ModelConfigModal from './components/ModelConfig'
import { ProjectState } from './types'
import { Save, CheckCircle } from 'lucide-react'
import { saveEpisode, loadEpisode } from './services/storageService'
import { setGlobalApiKey } from './services/aiService'
import { setLogCallback, clearLogCallback } from './services/renderLogService'
import { useAlert } from './components/GlobalAlert'
import { ProjectProvider, useProjectContext } from './contexts/ProjectContext'
import {
  checkCharacterSync,
  checkSceneSync,
  checkPropSync
} from './services/characterSyncService'
import AssetSyncBanner from './components/CharacterLibrary/AssetSyncBanner'
import logoImg from './logo.png'

const isNineGridGenerating = (status?: string): boolean =>
  status === 'generating_panels' ||
  status === 'generating_image' ||
  status === 'generating'

const clearInFlightGenerationStates = (episode: ProjectState): ProjectState => {
  const scriptData = episode.scriptData
    ? {
        ...episode.scriptData,
        characters: episode.scriptData.characters.map((char) => ({
          ...char,
          status: char.status === 'generating' ? 'failed' : char.status,
          turnaround:
            char.turnaround &&
            (char.turnaround.status === 'generating_panels' ||
              char.turnaround.status === 'generating_image')
              ? { ...char.turnaround, status: 'failed' as const }
              : char.turnaround,
          variations: char.variations.map((variation) => ({
            ...variation,
            status:
              variation.status === 'generating' ? 'failed' : variation.status
          }))
        })),
        scenes: episode.scriptData.scenes.map((scene) => ({
          ...scene,
          status: scene.status === 'generating' ? 'failed' : scene.status
        })),
        props: episode.scriptData.props.map((prop) => ({
          ...prop,
          status: prop.status === 'generating' ? 'failed' : prop.status
        }))
      }
    : null

  return {
    ...episode,
    isParsingScript: false,
    scriptGenerationCheckpoint: null,
    scriptData,
    shots: episode.shots.map((shot) => ({
      ...shot,
      keyframes: shot.keyframes?.map((kf) =>
        kf.status === 'generating' ? { ...kf, status: 'failed' as const } : kf
      ),
      interval:
        shot.interval?.status === 'generating'
          ? { ...shot.interval, status: 'failed' as const }
          : shot.interval,
      nineGrid:
        shot.nineGrid && isNineGridGenerating(shot.nineGrid.status)
          ? { ...shot.nineGrid, status: 'failed' as const }
          : shot.nineGrid
    }))
  }
}

function MobileWarning() {
  return (
    <div className="h-screen bg-[var(--bg-base)] flex items-center justify-center p-6">
      <div className="max-w-md text-center space-y-6">
        <img src={logoImg} alt="Logo" className="w-20 h-20 mx-auto mb-4" />
        <h1 className="text-2xl font-bold text-[var(--text-primary)] mb-2">
          BigBanana AI Director
        </h1>
        <div className="bg-[var(--bg-primary)] border border-[var(--border-primary)] rounded-xl p-8">
          <p className="text-[var(--text-tertiary)] text-base leading-relaxed mb-4">
            涓轰簡鑾峰緱鏈€浣充綋楠岋紝璇蜂娇鐢?PC 绔祻瑙堝櫒璁块棶銆俓n          </p>
          <p className="text-[var(--text-muted)] text-sm">
            鏈簲鐢ㄩ渶瑕佽緝澶х殑灞忓箷绌洪棿鍜屾闈㈢骇娴忚鍣ㄧ幆澧冩墠鑳芥甯歌繍琛屻€俓n          </p>
        </div>
      </div>
    </div>
  )
}

function EpisodeWorkspace() {
  const { episodeId } = useParams<{ episodeId: string }>()
  const navigate = useNavigate()
  const { showAlert } = useAlert()
  const {
    project,
    currentEpisode,
    setCurrentEpisode,
    updateProject: updateSeriesProject,
    updateEpisode,
    syncAllCharactersToEpisode,
    syncAllScenesToEpisode,
    syncAllPropsToEpisode
  } = useProjectContext()
  const [isGenerating, setIsGenerating] = useState(false)
  const [saveStatus, setSaveStatus] = useState<'saved' | 'saving' | 'unsaved'>(
    'saved'
  )
  const [showSaveStatus, setShowSaveStatus] = useState(false)
  const [showOnboarding, setShowOnboarding] = useState(false)
  const [showModelConfig, setShowModelConfig] = useState(false)
  const [isSidebarOpen, setIsSidebarOpen] = useState(true)
  const saveTimeoutRef = useRef<any>(null)
  const hideStatusTimeoutRef = useRef<any>(null)

  useEffect(() => {
    if (!episodeId) return
    loadEpisode(episodeId)
      .then((ep) => setCurrentEpisode(ep))
      .catch(() => navigate('/'))
    return () => setCurrentEpisode(null)
  }, [episodeId])

  useEffect(() => {
    if (currentEpisode) {
      setLogCallback((log) => {
        updateEpisode((prev) => ({
          ...prev,
          renderLogs: [...(prev.renderLogs || []), log]
        }))
      })
    } else {
      clearLogCallback()
    }
    return () => clearLogCallback()
  }, [currentEpisode?.id])

  useEffect(() => {
    if (!currentEpisode) return
    setSaveStatus('unsaved')
    setShowSaveStatus(true)
    if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current)
    saveTimeoutRef.current = setTimeout(async () => {
      setSaveStatus('saving')
      try {
        await saveEpisode(currentEpisode)
        setSaveStatus('saved')
      } catch (e) {
        console.error('Auto-save failed', e)
      }
    }, 1000)
    return () => {
      if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current)
    }
  }, [currentEpisode])

  useEffect(() => {
    if (saveStatus === 'saved') {
      if (hideStatusTimeoutRef.current)
        clearTimeout(hideStatusTimeoutRef.current)
      hideStatusTimeoutRef.current = setTimeout(
        () => setShowSaveStatus(false),
        2000
      )
    } else if (saveStatus === 'saving') {
      setShowSaveStatus(true)
      if (hideStatusTimeoutRef.current)
        clearTimeout(hideStatusTimeoutRef.current)
    }
    return () => {
      if (hideStatusTimeoutRef.current)
        clearTimeout(hideStatusTimeoutRef.current)
    }
  }, [saveStatus])

  useEffect(() => {
    if (!project || !currentEpisode) return
    if (currentEpisode.episodeNumber !== 1) return

    const projectTitle = (project.title || '').trim()
    const isProjectPlaceholder =
      !projectTitle ||
      projectTitle === '鏈懡鍚嶉」鐩? ||
      /^鏂板缓椤圭洰\s\d{4}-\d{2}-\d{2}\s\d{2}:\d{2}$/.test(projectTitle)

    if (!isProjectPlaceholder) return

    const candidateTitle = (
      currentEpisode.scriptData?.title ||
      currentEpisode.title ||
      ''
    ).trim()
    if (!candidateTitle) return
    if (/^绗琝\s*\d+\s*闆?/u.test(candidateTitle)) return
    if (candidateTitle === projectTitle) return

    updateSeriesProject({ title: candidateTitle })
  }, [project, currentEpisode, updateSeriesProject])

  const handleUpdateProject = (
    updates: Partial<ProjectState> | ((prev: ProjectState) => ProjectState)
  ) => {
    updateEpisode(updates)
  }

  const setStage = (
    stage:
      | 'script'
      | 'assets'
      | 'director'
      | 'lark-director'
      | 'export'
      | 'prompts'
  ) => {
    if (isGenerating) {
      showAlert(
        '褰撳墠姝ｅ湪鎵ц鐢熸垚浠诲姟锛屽垏鎹㈤〉闈細瀵艰嚧鐢熸垚鏁版嵁涓㈠け銆俓
\n纭畾瑕佺寮€褰撳墠椤甸潰鍚楋紵',
        {
          title: '鐢熸垚浠诲姟杩涜涓?,
          type: 'warning',
          showCancel: true,
          confirmText: '纭畾绂诲紑',
          cancelText: '缁х画绛夊緟',
          onConfirm: () => {
            setIsGenerating(false)
            updateEpisode((prev) => ({
              ...clearInFlightGenerationStates(prev),
              stage
            }))
          }
        }
      )
      return
    }
    handleUpdateProject({ stage })
  }

  const handleExit = async () => {
    if (isGenerating) {
      showAlert(
        '褰撳墠姝ｅ湪鎵ц鐢熸垚浠诲姟锛岄€€鍑轰細瀵艰嚧鏁版嵁涓㈠け銆俓
\n纭畾瑕侀€€鍑哄悧锛?,
        {
          title: '鐢熸垚浠诲姟杩涜涓?,
          type: 'warning',
          showCancel: true,
          confirmText: '纭畾閫€鍑?,
          cancelText: '缁х画绛夊緟',
          onConfirm: async () => {
            setIsGenerating(false)
            if (currentEpisode) {
              const cleanedEpisode =
                clearInFlightGenerationStates(currentEpisode)
              await saveEpisode(cleanedEpisode)
            }
            navigate(`/project/${currentEpisode?.projectId || ''}`)
          }
        }
      )
      return
    }
    if (currentEpisode) await saveEpisode(currentEpisode)
    navigate(`/project/${currentEpisode?.projectId || ''}`)
  }

  if (!currentEpisode) {
    return (
      <div className="h-screen flex items-center justify-center text-[var(--text-muted)]">
        鍔犺浇涓?..
      </div>
    )
  }

  const renderStage = () => {
    switch (currentEpisode.stage) {
      case 'script':
        return (
          <StageScript
            project={currentEpisode}
            updateProject={handleUpdateProject}
            onShowModelConfig={() => setShowModelConfig(true)}
            onGeneratingChange={setIsGenerating}
          />
        )
      case 'assets':
        return (
          <StageAssets
            project={currentEpisode}
            updateProject={handleUpdateProject}
            onGeneratingChange={setIsGenerating}
          />
        )
      case 'director':
        return (
          <StageDirector
            project={currentEpisode}
            updateProject={handleUpdateProject}
            onGeneratingChange={setIsGenerating}
          />
        )
      case 'lark-director':
        return (
          <LarkDirector
            project={currentEpisode}
            updateProject={handleUpdateProject}
            onGeneratingChange={setIsGenerating}
          />
        )
      case 'export':
        return <StageExport project={currentEpisode} />
      case 'prompts':
        return (
          <StagePrompts
            project={currentEpisode}
            updateProject={handleUpdateProject}
          />
        )
      default:
        return <div className="text-[var(--text-primary)]">鏈煡闃舵</div>
    }
  }

  const displayEpisodeTitle =
    project &&
    currentEpisode.episodeNumber === 1 &&
    currentEpisode.title?.trim() === project.title?.trim()
      ? `绗?${currentEpisode.episodeNumber} 闆哷
      : currentEpisode.title
  const episodeLabel = project
    ? `${project.title} / ${displayEpisodeTitle}`
    : displayEpisodeTitle

  return (
    <div className="flex h-screen bg-[var(--bg-secondary)] font-sans text-[var(--text-secondary)] selection:bg-[var(--accent-bg)]">
      <Sidebar
        isOpen={isSidebarOpen}
        onToggle={() => setIsSidebarOpen(!isSidebarOpen)}
        currentStage={currentEpisode.stage}
        setStage={setStage}
        onExit={handleExit}
        projectName={episodeLabel}
        onShowOnboarding={() => {
          resetOnboarding()
          setShowOnboarding(true)
        }}
        onShowModelConfig={() => setShowModelConfig(true)}
        isNavigationLocked={isGenerating}
        episodeInfo={
          project
            ? {
                projectId: project.id,
                projectTitle: project.title,
                episodeTitle: displayEpisodeTitle
              }
            : undefined
        }
        onGoToProject={
          project ? () => navigate(`/project/${project.id}`) : undefined
        }
      />
      <main
        className={`${isSidebarOpen ? 'ml-72' : 'ml-0'} transition-all duration-300 flex-1 h-screen overflow-hidden relative`}
      >
        {project &&
          currentEpisode &&
          (() => {
            const { outdatedRefs: outdatedCharacters } = checkCharacterSync(
              currentEpisode,
              project
            )
            const { outdatedRefs: outdatedScenes } = checkSceneSync(
              currentEpisode,
              project
            )
            const { outdatedRefs: outdatedProps } = checkPropSync(
              currentEpisode,
              project
            )

            return (
              <>
                <AssetSyncBanner
                  title="Characters"
                  outdatedRefs={outdatedCharacters.map((ref) => ({
                    assetId: ref.characterId,
                    syncedVersion: ref.syncedVersion
                  }))}
                  resolveName={(assetId) =>
                    project.characterLibrary.find((ch) => ch.id === assetId)
                      ?.name || assetId
                  }
                  onSyncAll={syncAllCharactersToEpisode}
                />
                <AssetSyncBanner
                  title="Scenes"
                  outdatedRefs={outdatedScenes.map((ref) => ({
                    assetId: ref.sceneId,
                    syncedVersion: ref.syncedVersion
                  }))}
                  resolveName={(assetId) =>
                    project.sceneLibrary.find((sc) => sc.id === assetId)
                      ?.location || assetId
                  }
                  onSyncAll={syncAllScenesToEpisode}
                />
                <AssetSyncBanner
                  title="Props"
                  outdatedRefs={outdatedProps.map((ref) => ({
                    assetId: ref.propId,
                    syncedVersion: ref.syncedVersion
                  }))}
                  resolveName={(assetId) =>
                    project.propLibrary.find((pr) => pr.id === assetId)?.name ||
                    assetId
                  }
                  onSyncAll={syncAllPropsToEpisode}
                />
              </>
            )
          })()}
        {renderStage()}
        {showSaveStatus && (
          <div className="absolute top-4 right-6 pointer-events-none flex items-center gap-2 text-xs font-mono text-[var(--text-tertiary)] bg-[var(--overlay-medium)] px-2 py-1 rounded-full backdrop-blur-sm z-50">
            {saveStatus === 'saving' ? (
              <>
                <Save className="w-3 h-3 animate-pulse" />
                淇濆瓨涓?..
              </>
            ) : (
              <>
                <CheckCircle className="w-3 h-3 text-[var(--success)]" />
                宸蹭繚瀛榎n              </>
            )}
          </div>
        )}
      </main>
      {showOnboarding && (
        <Onboarding
          onComplete={() => setShowOnboarding(false)}
          onQuickStart={() => setShowOnboarding(false)}
          currentApiKey=""
          onSaveApiKey={() => {}}
        />
      )}
      <ModelConfigModal
        isOpen={showModelConfig}
        onClose={() => setShowModelConfig(false)}
      />
    </div>
  )
}

function AppRoutes() {
  const navigate = useNavigate()
  const [showOnboarding, setShowOnboarding] = useState(false)
  const [showModelConfig, setShowModelConfig] = useState(false)
  const [apiKey, setApiKeyState] = useState('')

  useEffect(() => {
    const storedKey = localStorage.getItem('antsk_api_key')
    if (storedKey) {
      setApiKeyState(storedKey)
      setGlobalApiKey(storedKey)
    }
    if (shouldShowOnboarding()) setShowOnboarding(true)
  }, [])

  useEffect(() => {
    const handleError = (event: ErrorEvent) => {
      if (
        event.error?.message?.includes('API Key missing') ||
        event.error?.message?.includes('AntSK API Key')
      ) {
        setShowModelConfig(true)
        event.preventDefault()
      }
    }
    const handleRejection = (event: PromiseRejectionEvent) => {
      if (
        event.reason?.message?.includes('API Key missing') ||
        event.reason?.message?.includes('AntSK API Key')
      ) {
        setShowModelConfig(true)
        event.preventDefault()
      }
    }
    window.addEventListener('error', handleError)
    window.addEventListener('unhandledrejection', handleRejection)
    return () => {
      window.removeEventListener('error', handleError)
      window.removeEventListener('unhandledrejection', handleRejection)
    }
  }, [])

  const handleSaveApiKey = (key: string) => {
    if (key) {
      setApiKeyState(key)
      setGlobalApiKey(key)
      localStorage.setItem('antsk_api_key', key)
    } else {
      setApiKeyState('')
      setGlobalApiKey('')
      localStorage.removeItem('antsk_api_key')
    }
  }

  return (
    <>
      <Routes>
        <Route
          path="/"
          element={
            <Dashboard
              onOpenProject={(proj) => {
                if (proj.projectId) navigate(`/project/${proj.projectId}`)
                else navigate(`/project/${proj.id}/episode/${proj.id}`)
              }}
              onShowOnboarding={() => {
                resetOnboarding()
                setShowOnboarding(true)
              }}
              onShowModelConfig={() => setShowModelConfig(true)}
            />
          }
        />
        <Route
          path="/project/:projectId"
          element={
            <ProjectProvider>
              <ProjectOverview />
            </ProjectProvider>
          }
        />
        <Route
          path="/project/:projectId/characters"
          element={
            <ProjectProvider>
              <CharacterLibraryPage />
            </ProjectProvider>
          }
        />
        <Route
          path="/project/:projectId/episode/:episodeId"
          element={
            <ProjectProvider>
              <EpisodeWorkspace />
            </ProjectProvider>
          }
        />
        <Route path="/account" element={<NewApiConsole />} />
      </Routes>
      {showOnboarding && (
        <Onboarding
          onComplete={() => setShowOnboarding(false)}
          onQuickStart={() => setShowOnboarding(false)}
          currentApiKey={apiKey}
          onSaveApiKey={handleSaveApiKey}
        />
      )}
      <ModelConfigModal
        isOpen={showModelConfig}
        onClose={() => setShowModelConfig(false)}
      />
    </>
  )
}

function App() {
  const [isMobile, setIsMobile] = useState(false)

  useEffect(() => {
    const check = () =>
      setIsMobile(
        /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(
          navigator.userAgent
        ) || window.innerWidth < 1024
      )
    check()
    window.addEventListener('resize', check)
    return () => window.removeEventListener('resize', check)
  }, [])

  if (isMobile) return <MobileWarning />
  return <AppRoutes />
}

export default App

import React, { useEffect, useMemo, useState } from 'react'
import {
  Users,
  MapPin,
  Package,
  Upload,
  Trash2,
  RotateCcw,
  Save,
  Link2
} from 'lucide-react'
import { Character, Scene, Prop } from '../../types'

export type LibraryAssetType = 'character' | 'scene' | 'prop'
export type LibraryAsset = Character | Scene | Prop

interface AssetLibraryEditorCardProps {
  type: LibraryAssetType
  asset: LibraryAsset
  refCount: number
  onSave: (nextAsset: LibraryAsset) => void
  onDelete: () => void
  onUploadImage: (file: File) => void
  onPreviewImage: (imageUrl: string) => void
}

const EDITABLE_FIELDS: Record<LibraryAssetType, string[]> = {
  character: [
    'name',
    'gender',
    'age',
    'personality',
    'coreFeatures',
    'visualPrompt'
  ],
  scene: ['location', 'time', 'atmosphere', 'visualPrompt'],
  prop: ['name', 'category', 'description', 'visualPrompt']
}

const getAssetTitle = (type: LibraryAssetType, asset: LibraryAsset): string => {
  if (type === 'character') return (asset as Character).name
  if (type === 'scene') return (asset as Scene).location
  return (asset as Prop).name
}

const getAssetSubtitle = (
  type: LibraryAssetType,
  asset: LibraryAsset
): string => {
  if (type === 'character') {
    const character = asset as Character
    return `${character.gender || '-'} 路 ${character.age || '-'}`
  }
  if (type === 'scene') {
    const scene = asset as Scene
    return `${scene.time || '-'} 路 ${scene.atmosphere || '-'}`
  }
  return (asset as Prop).category || '-'
}

const getAssetIcon = (type: LibraryAssetType) => {
  if (type === 'character') return Users
  if (type === 'scene') return MapPin
  return Package
}

const getTypeLabel = (type: LibraryAssetType): string => {
  if (type === 'character') return '瑙掕壊'
  if (type === 'scene') return '鍦烘櫙'
  return '閬撳叿'
}

const AssetLibraryEditorCard: React.FC<AssetLibraryEditorCardProps> = ({
  type,
  asset,
  refCount,
  onSave,
  onDelete,
  onUploadImage,
  onPreviewImage
}) => {
  const [draft, setDraft] = useState<LibraryAsset>(asset)
  const AssetIcon = getAssetIcon(type)

  useEffect(() => {
    setDraft(asset)
  }, [asset])

  const hasChanges = useMemo(() => {
    const fields = EDITABLE_FIELDS[type]
    return fields.some((field) => {
      const oldValue = ((asset as any)[field] ?? '').toString()
      const newValue = ((draft as any)[field] ?? '').toString()
      return oldValue !== newValue
    })
  }, [type, asset, draft])

  const updateField = (field: string, value: string) => {
    setDraft((prev) => ({ ...(prev as any), [field]: value }) as LibraryAsset)
  }

  const getValue = (field: string): string =>
    ((draft as any)[field] ?? '').toString()
  const previewImage = (draft as any).referenceImage as string | undefined
  const version = (draft as any).version || 1

  return (
    <div className="bg-[var(--bg-primary)] border border-[var(--border-primary)] rounded-xl overflow-hidden hover:border-[var(--border-secondary)] transition-colors">
      <div className="aspect-video bg-[var(--bg-elevated)] relative">
        {previewImage ? (
          <img
            src={previewImage}
            alt={getAssetTitle(type, draft)}
            className="w-full h-full object-cover cursor-pointer"
            onClick={() => onPreviewImage(previewImage)}
          />
        ) : (
          <div className="w-full h-full flex flex-col items-center justify-center text-[var(--text-muted)]">
            <AssetIcon className="w-9 h-9 opacity-30 mb-2" />
            <span className="text-[10px] font-mono uppercase tracking-widest">
              {getTypeLabel(type)}
            </span>
          </div>
        )}
        <div className="absolute left-2 top-2 px-2 py-0.5 text-[9px] font-mono rounded bg-[var(--accent-bg)] text-[var(--accent-text)] uppercase tracking-widest">
          v{version}
        </div>
        {refCount > 0 && (
          <div className="absolute right-2 top-2 px-2 py-0.5 text-[9px] font-mono rounded bg-[var(--bg-base)]/80 text-[var(--text-tertiary)] flex items-center gap-1">
            <Link2 className="w-3 h-3" />
            {refCount} 闆嗗紩鐢╘n          </div>
        )}
      </div>

      <div className="p-4 space-y-3">
        <div>
          <div className="text-sm font-bold text-[var(--text-primary)] line-clamp-1">
            {getAssetTitle(type, draft)}
          </div>
          <div className="text-[10px] text-[var(--text-muted)] font-mono mt-1 line-clamp-1">
            {getAssetSubtitle(type, draft)}
          </div>
        </div>

        {type === 'character' && (
          <>
            <input
              value={getValue('name')}
              onChange={(e) => updateField('name', e.target.value)}
              placeholder="瑙掕壊鍚嶇О"
              className="w-full px-3 py-2 bg-[var(--bg-primary)] border border-[var(--border-primary)] rounded text-xs text-[var(--text-primary)] placeholder:text-[var(--text-muted)] focus:outline-none focus:border-[var(--border-secondary)]"
            />
            <div className="grid grid-cols-2 gap-2">
              <input
                value={getValue('gender')}
                onChange={(e) => updateField('gender', e.target.value)}
                placeholder="鎬у埆"
