image":"https://everphoto-media.jianying.com/download/bucket/everphoto-jianying-assets_0171ccb7-d72e-4a9a-b061-3744361f6c05?X-Everphoto-Sum=74f5a1101e64ac618575af72b606d695503d8488&X-Everphoto-Token=AAAAAAAAAAAAAAAAAAAAAKMaDNP8pfLTxE1YdgqiL8uU4GrXBW25-4aqUCNC6wyxl5GGlLvEe9YlUqikV7C2xCAwcBdVsD3ZnGXvB-ReJPg"}'>@娉界淮灏?鍩虹褰㈣薄</span>鐨勬墜鎸囩┛杩?span data-type="mention" data-id="閲戝彂濂冲" data-item='{"type":"character","name":"閲戝彂濂冲", "image":"https://everphoto-media.jianying.com/download/bucket/everphoto-jianying-assets_a4fc59f5-7611-4299-99bb-12fcce1a1080?X-Everphoto-Sum=461daeaa265f7a817e29c11d4c7ed8040b53a73d&X-Everphoto-Token=AAAAAAAAAAAAAAAAAAAAANm8DHahmSuaIm1wwhHZzGyzzclIKCtUB2Bz1iR3srmp3NaGmpcCp6NJIPQOHYhZnPtydlFIi_z6qN6SvtvfLDE"}'>@閲戝彂濂冲-鍩虹褰㈣薄</span>鐨勯噾鍙戯紝鍢村攪鍘嬪湪濂硅剸棰堜笂銆傞暅澶村垏鎹㈠埌<span data-type="mention" data-id="濉炶タ鑾変簹" data-item='{"type":"character","name":"濉炶タ鑾変簹", "image":"https://everphoto-media.jianying.com/download/bucket/everphoto-jianying-assets_0458d898-e5eb-4a8e-adff-ca7bad6b99bd?X-Everphoto-Sum=a40b8b9b7cefc363e372d8f84bca80841b585784&X-Everphoto-Token=AAAAAAAAAAAAAAAAAAAAANm8DHahmSuaIm1wwhHZzGzbwaxD6UP4qu4uZ9Okx7L1jl56Kccp9AVa1O3F1INOnYni1VIl7JKa6MOHSTN5IyY"}'>@濉炶タ鑾変簹-鍩虹褰㈣薄</span>鐨勭溂閮ㄧ壒鍐欙紝濂圭灣瀛斿井棰わ紝闅忓悗闀滃ご涓嬬Щ锛屽ス鐨勬墜绱х揣鏀ヤ綇鏂囦欢锛屾寚鑺傚洜鐢ㄥ姏鑰屽彂鐧姐€傜敾闈腑鎵€鏈夎鑹插叏绋嬩笉璇磋瘽銆?/p>`

const ScriptEditorRich: React.FC<Props> = ({
  project,
  projectLibrary,
  initialContent
}) => {
  const [isEditing, setIsEditing] = useState(false)
  const [savedContent, setSavedContent] = useState(
    initialContent || DEFAULT_SCRIPT
  )

  const projectRef = useRef(project)
  const projectLibraryRef = useRef(projectLibrary || null)
  const mentionPickerRef = useRef<{
    popup?: Instance[]
    component?: ReactRenderer
    removeKeydown?: () => void
  } | null>(null)

  const destroyMentionPicker = () => {
    mentionPickerRef.current?.removeKeydown?.()
    mentionPickerRef.current?.popup?.[0]?.destroy()
    mentionPickerRef.current?.component?.destroy()
    mentionPickerRef.current = null
  }

  useEffect(() => {
    projectRef.current = project
  }, [project])
  useEffect(() => {
    projectLibraryRef.current = projectLibrary || null
  }, [projectLibrary])

  useEffect(() => {
    return () => {
      destroyMentionPicker()
    }
  }, [])

  const editor = useEditor({
    extensions: [
      StarterKit,
      DurationTag,
      CustomMention.configure({
        HTMLAttributes: {
          class: 'mention'
        },
        suggestion: {
          ...getSuggestion(
            () => projectRef.current,
            () => projectLibraryRef.current
          ),
          allowedPrefixes: null, // null allows any prefix in Tiptap
          allowSpaces: true
        }
      })
    ],
    content: savedContent,
    editable: isEditing,
    editorProps: {
      attributes: {
        class: 'focus:outline-none min-h-[200px] outline-none'
      },
      handleClickOn: (view, pos, node, nodePos, event, direct) => {
        if (node.type.name === 'mention' && view.editable) {
          event.preventDefault()
          destroyMentionPicker()
          const scriptItems = buildMentionItems(projectRef.current, '')
          const libraryItems = buildProjectLibraryMentionItems(
            projectLibraryRef.current,
            ''
          )
          const target = event.target as HTMLElement | null
          const getAnchorRect = () =>
            target?.getBoundingClientRect?.() ||
            event.currentTarget?.getBoundingClientRect?.()
          const component = new ReactRenderer(MentionList, {
            props: {
              items: scriptItems,
              libraryItems,
              onAddFromLibrary: () => {},
              command: (payload: any) => {
                const selected = payload?.itemData || payload
                const currentNode = view.state.doc.nodeAt(nodePos)
                if (!currentNode || currentNode.type.name !== 'mention') {
                  destroyMentionPicker()
                  return
                }

                const nextLabel =
                  selected?.name ||
                  payload?.label ||
                  payload?.id ||
                  currentNode.attrs.label ||
                  currentNode.attrs.id
                const nextId = selected?.id || payload?.id || nextLabel

                const tr = view.state.tr.setNodeMarkup(nodePos, undefined, {
                  ...currentNode.attrs,
                  id: nextId,
                  label: nextLabel,
                  itemData: selected
                })
                view.dispatch(tr)
                view.focus()
                destroyMentionPicker()
              }
            },
            editor
          })

          if (!getAnchorRect()) {
            component.destroy()
            return true
          }

          const popup = tippy('body', {
            getReferenceClientRect: getAnchorRect,
            appendTo: () => document.body,
            content: component.element,
            showOnCreate: true,
            interactive: true,
            trigger: 'manual',
            placement: 'bottom-start',
            hideOnClick: true,
            theme: 'mention-picker',
            arrow: false,
            maxWidth: 'none'
          })

          const onKeyDown = (keydownEvent: KeyboardEvent) => {
            if (keydownEvent.key === 'Escape') {
              keydownEvent.preventDefault()
              destroyMentionPicker()
              return
            }
            const handled = (component.ref as any)?.onKeyDown?.({
              event: keydownEvent
            })
            if (handled) {
              keydownEvent.preventDefault()
              keydownEvent.stopPropagation()
            }
          }
          document.addEventListener('keydown', onKeyDown, true)

          mentionPickerRef.current = {
            popup,
            component,
            removeKeydown: () =>
              document.removeEventListener('keydown', onKeyDown, true)
          }
          return true
        }
        return false
      }
    }
  })

  useEffect(() => {
    if (editor) {
      editor.setEditable(isEditing)
    }
  }, [isEditing, editor])

  return (
    <div className="bg-[var(--bg-surface)] border border-[var(--border-primary)] rounded-xl p-4 h-full min-h-0 flex flex-col shadow-sm transition-all duration-200">
      <style>{`
        .ProseMirror p {
          margin-bottom: 0.7em;
          line-height: 2;
        }
        .ProseMirror p.is-editor-empty:first-child::before {
          content: attr(data-placeholder);
          float: left;
          color: var(--text-muted);
          pointer-events: none;
          height: 0;
        }
        .hide-number-spinners::-webkit-inner-spin-button,
        .hide-number-spinners::-webkit-outer-spin-button {
          -webkit-appearance: none;
          margin: 0;
        }
        .hide-number-spinners {
          -moz-appearance: textfield;
        }
        .ProseMirror[contenteditable="false"] .duration-input {
          pointer-events: none;
        }
        .tippy-box[data-theme~="mention-picker"] {
          background: transparent !important;
          box-shadow: none !important;
          border: none !important;
        }
        .tippy-box[data-theme~="mention-picker"] > .tippy-content {
          padding: 0 !important;
        }
        .tippy-box[data-theme~="mention-picker"] > .tippy-arrow {
          display: none !important;
        }
      `}</style>
      <div className="flex-1 min-h-0 relative flex flex-col cursor-text overflow-hidden">
        <EditorContent
          editor={editor}
          className="flex-1 min-h-0 w-full overflow-y-auto bg-transparent text-[13px] leading-relaxed text-[var(--text-primary)] pr-1"
        />
      </div>

      <div className="mt-4 flex items-center justify-end gap-3 pointer-events-auto shrink-0">
        {isEditing ? (
          <>
            <button
              onClick={(e) => {
                e.stopPropagation()
                setIsEditing(false)
                editor?.commands.setContent(savedContent)
              }}
              className="px-6 py-2 rounded-full text-[13px] font-medium bg-white text-black border border-gray-200 hover:bg-gray-50 transition-colors shadow-sm"
            >
              鍙栨秷
            </button>
            <button
              onClick={(e) => {
                e.stopPropagation()
                setIsEditing(false)
                if (editor) {
                  setSavedContent(editor.getHTML())
                }
              }}
              className="px-6 py-2 rounded-full text-[13px] font-medium bg-black text-white hover:bg-gray-800 transition-colors shadow-sm"
            >
              淇濆瓨
            </button>
          </>
        ) : (
          <>
            <button
              onClick={(e) => {
                e.stopPropagation()
                setIsEditing(true)
                setTimeout(() => editor?.commands.focus(), 0)
              }}
              className="px-6 py-2 rounded-full text-[13px] font-medium bg-white text-black border border-gray-200 hover:bg-gray-50 transition-colors shadow-sm flex items-center gap-2"
            >
              <Edit2 className="w-3.5 h-3.5" />
              缂栬緫鑴氭湰
            </button>
            <button
              onClick={(e) => {
                e.stopPropagation()
              }}
              className="px-6 py-2 rounded-full text-[13px] font-medium bg-black text-white hover:bg-gray-800 transition-colors shadow-sm flex items-center gap-2"
            >
              <Film className="w-3.5 h-3.5" />
              鍐嶆鐢熸垚
            </button>
          </>
        )}
      </div>
    </div>
  )
}

export default ScriptEditorRich

