import { ReactRenderer } from '@tiptap/react'
import tippy, { Instance } from 'tippy.js'
import 'tippy.js/dist/tippy.css'
import MentionList from './MentionList'

export interface MentionItem {
  id: string
  type: 'character' | 'scene' | 'prop'
  name: string
  desc: string
  image?: string
}

const dedupeMentionItems = (items: MentionItem[]): MentionItem[] => {
  const seen = new Set<string>()
  return items.filter((item) => {
    const key = `${item.type}:${item.name}`
    if (seen.has(key)) return false
    seen.add(key)
    return true
  })
}

export function buildProjectLibraryMentionItems(
  projectLibrary: any,
  query = ''
): MentionItem[] {
  const allCharacters = projectLibrary?.characterLibrary || []
  const allScenes = projectLibrary?.sceneLibrary || []
  const allProps = projectLibrary?.propLibrary || []
  const resources: MentionItem[] = [
    ...allCharacters.map((c: any) => ({
      id: c.id || c.name,
      type: 'character' as const,
      name: c.name,
      desc: '鍩虹褰㈣薄-鍩虹褰㈣薄',
      image: c.referenceImage
    })),
    ...allScenes.map((s: any) => ({
      id: s.id || s.location,
      type: 'scene' as const,
      name: s.location,
      desc: `${s.location}_0`,
      image: s.referenceImage
    })),
    ...allProps.map((p: any) => ({
      id: p.id || p.name,
      type: 'prop' as const,
      name: p.name,
      desc: p.category || '閬撳叿',
      image: p.referenceImage
    }))
  ]

  const normalizedQuery = (query || '').trim().toLowerCase()
  if (!normalizedQuery) {
    return dedupeMentionItems(resources).slice(0, 80)
  }

  return dedupeMentionItems(resources)
    .filter((item) => (item.name || '').toLowerCase().includes(normalizedQuery))
    .slice(0, 80)
}

export function buildMentionItems(project: any, query = ''): MentionItem[] {
  const allCharacters = project?.scriptData?.characters || []
  const allScenes = project?.scriptData?.scenes || []
  const allProps = project?.scriptData?.props || []
  const resources: MentionItem[] = [
    ...allCharacters.map((c: any) => ({
      id: c.id || c.name,
      type: 'character' as const,
      name: c.name,
      desc: '鍩虹褰㈣薄-鍩虹褰㈣薄',
      image: c.referenceImage
    })),
    ...allScenes.map((s: any) => ({
      id: s.id || s.location,
      type: 'scene' as const,
      name: s.location,
      desc: `${s.location}_0`,
      image: s.referenceImage
    })),
    ...allProps.map((p: any) => ({
      id: p.id || p.name,
      type: 'prop' as const,
      name: p.name,
      desc: p.category || '閬撳叿',
      image: p.referenceImage
    }))
  ]

  const normalizedQuery = (query || '').trim().toLowerCase()
  if (!normalizedQuery) {
    return dedupeMentionItems(resources).slice(0, 80)
  }

  return dedupeMentionItems(resources)
    .filter((item) => (item.name || '').toLowerCase().includes(normalizedQuery))
    .slice(0, 80)
}

export default function getSuggestion(
  getProject: () => any,
  getProjectLibrary?: () => any
) {
  return {
    char: '@',
    items: ({ query }: { query: string }) => {
      const scriptItems = buildMentionItems(getProject(), query)
      const libraryItems = buildProjectLibraryMentionItems(
        getProjectLibrary?.(),
        query
      )
      return dedupeMentionItems([...scriptItems, ...libraryItems]).slice(0, 80)
    },

    render: () => {
      let component: ReactRenderer
      let popup: Instance[]
      const createAddFromLibraryHandler = () => () => {}

      return {
        onStart: (props: any) => {
          const libraryItems = buildProjectLibraryMentionItems(
            getProjectLibrary?.(),
            ''
          )
          component = new ReactRenderer(MentionList, {
            props: {
              ...props,
              libraryItems,
              onAddFromLibrary: createAddFromLibraryHandler()
            },
            editor: props.editor
          })

          if (!props.clientRect) {
            return
          }

          popup = tippy('body', {
            getReferenceClientRect: props.clientRect,
            appendTo: () => document.body,
            content: component.element,
            showOnCreate: true,
            interactive: true,
            trigger: 'manual',
            placement: 'bottom-start',
            theme: 'mention-picker',
            arrow: false,
            maxWidth: 'none'
          })
        },
        onUpdate(props: any) {
          const libraryItems = buildProjectLibraryMentionItems(
            getProjectLibrary?.(),
            ''
          )
          component.updateProps({
            ...props,
            libraryItems,
            onAddFromLibrary: createAddFromLibraryHandler()
          })

          if (!props.clientRect) {
            return
          }

          if (!popup) {
            popup = tippy('body', {
              getReferenceClientRect: props.clientRect,
              appendTo: () => document.body,
              content: component.element,
              showOnCreate: true,
              interactive: true,
              trigger: 'manual',
              placement: 'bottom-start',
              theme: 'mention-picker',
              arrow: false,
              maxWidth: 'none'
            })
          } else if (popup[0]) {
            popup[0].setProps({
              getReferenceClientRect: props.clientRect
            })
          }
        },

        onKeyDown(props: any) {
          if (props.event.key === 'Escape') {
            popup?.[0]?.hide()
            return true
          }

          return (component.ref as any)?.onKeyDown(props)
        },

        onExit() {
          popup?.[0]?.destroy()
          component?.destroy()
        }
      }
    }
  }
}

/**
 * 娣诲姞妯″瀷琛ㄥ崟缁勪欢
 * 鏀寔鑷畾涔夋彁渚涘晢鍜?endpoint
 */

import React, { useEffect, useState } from 'react'
import { Check, X } from 'lucide-react'
import {
  ModelType,
  ModelDefinition,
  ImageApiFormat,
  AudioOutputFormat,
  ChatModelParams,
  ImageModelParams,
  VideoModelParams,
  AudioModelParams,
  DEFAULT_CHAT_PARAMS,
  DEFAULT_IMAGE_PARAMS,
  DEFAULT_IMAGE_PARAMS_OPENAI,
  DEFAULT_VIDEO_PARAMS_SORA,
  DEFAULT_VIDEO_PARAMS_VEO,
  DEFAULT_VIDEO_PARAMS_DOUBAO_SEEDANCE,
  DEFAULT_AUDIO_PARAMS
} from '../../types/model'
import { getProviders, addProvider } from '../../services/modelRegistry'
import { useAlert } from '../GlobalAlert'

interface AddModelFormProps {
  type: ModelType
  onSave: (model: Omit<ModelDefinition, 'id' | 'isBuiltIn'>) => void
  onCancel: () => void
}

const AddModelForm: React.FC<AddModelFormProps> = ({
  type,
  onSave,
  onCancel
}) => {
  const existingProviders = getProviders()
  const { showAlert } = useAlert()

  const [name, setName] = useState('')
  const [apiModel, setApiModel] = useState('')
  const [description, setDescription] = useState('')
  const [endpoint, setEndpoint] = useState('')
  const [apiKey, setApiKey] = useState('')
  const [imageApiFormat, setImageApiFormat] = useState<ImageApiFormat>('gemini')
  const [videoMode, setVideoMode] = useState<'sync' | 'async' | 'task'>('sync')
  const [audioVoice, setAudioVoice] = useState<string>(
    DEFAULT_AUDIO_PARAMS.defaultVoice
  )
  const [audioOutputFormat, setAudioOutputFormat] = useState<AudioOutputFormat>(
    DEFAULT_AUDIO_PARAMS.outputFormat
  )

  // 鎻愪緵鍟嗛厤缃甛n  const [selectedProviderId, setSelectedProviderId] = useState(
    existingProviders[0]?.id || 'antsk'
  )

  useEffect(() => {
    if (type !== 'video' || videoMode !== 'task') return
    const volcengineProvider = existingProviders.find(
      (p) =>
        p.id === 'volcengine' || p.baseUrl.toLowerCase().includes('volces.com')
    )
    if (volcengineProvider) {
      setSelectedProviderId(volcengineProvider.id)
    }
  }, [type, videoMode])

  const handleSave = () => {
    if (!name.trim()) {
      showAlert('璇疯緭鍏ユā鍨嬪悕绉?, { type: 'error' })
      return
    }
    if (!apiModel.trim()) {
      showAlert('璇疯緭鍏ユā鍨嬫爣璇?, { type: 'error' })
      return
    }
    if (!selectedProviderId) {
      showAlert('璇烽€夋嫨鎻愪緵鍟?, { type: 'error' })
      return
    }

    const providerId = selectedProviderId

    // 鏍规嵁妯″瀷绫诲瀷璁剧疆榛樿鍙傛暟
    let params:
      | ChatModelParams
      | ImageModelParams
      | VideoModelParams
      | AudioModelParams
    let resolvedEndpoint = endpoint.trim() || undefined

    if (type === 'chat') {
      params = { ...DEFAULT_CHAT_PARAMS }
      if (!resolvedEndpoint) resolvedEndpoint = '/v1/chat/completions'
    } else if (type === 'image') {
      params =
        imageApiFormat === 'openai'
          ? { ...DEFAULT_IMAGE_PARAMS_OPENAI }
          : { ...DEFAULT_IMAGE_PARAMS }
      if (!resolvedEndpoint) {
        resolvedEndpoint =
          imageApiFormat === 'openai'
            ? '/v1/images/generations'
            : '/v1beta/models/{model}:generateContent'
      }
    } else if (type === 'video') {
      params =
        videoMode === 'sync'
          ? { ...DEFAULT_VIDEO_PARAMS_VEO }
          : videoMode === 'task'
            ? { ...DEFAULT_VIDEO_PARAMS_DOUBAO_SEEDANCE }
            : { ...DEFAULT_VIDEO_PARAMS_SORA }

      if (!resolvedEndpoint) {
        resolvedEndpoint =
          videoMode === 'sync'
            ? '/v1/chat/completions'
            : videoMode === 'task'
              ? '/api/v3/contents/generations/tasks'
              : '/v1/videos'
      }
    } else {
      params = {
        ...DEFAULT_AUDIO_PARAMS,
        defaultVoice: audioVoice.trim() || DEFAULT_AUDIO_PARAMS.defaultVoice,
        outputFormat: audioOutputFormat
      }
      if (!resolvedEndpoint) {
        resolvedEndpoint = '/v1/chat/completions'
      }
    }

    const model: Omit<ModelDefinition, 'id' | 'isBuiltIn'> = {
      name: name.trim(),
      apiModel: apiModel.trim(),
      type,
      providerId,
      endpoint: resolvedEndpoint,
      description: description.trim() || undefined,
      apiKey: apiKey.trim() || undefined,
      isEnabled: true,
      params
    } as any

    onSave(model)
  }

  return (
    <div className="bg-[var(--bg-elevated)]/50 border border-[var(--border-secondary)] rounded-lg p-4 space-y-4">
      <h4 className="text-sm font-bold text-[var(--text-primary)]">
        娣诲姞鑷畾涔夋ā鍨媆n      </h4>

      {/* 鍩虹淇℃伅 */}
      <div className="grid grid-cols-2 gap-4">
        <div>
          <label className="text-[10px] text-[var(--text-tertiary)] block mb-1">
            妯″瀷鍚嶇О *
          </label>
          <input
            type="text"
            value={name}
            onChange={(e) => setName(e.target.value)}
            placeholder="濡傦細GPT-4 Turbo"
            className="w-full bg-[var(--bg-hover)] border border-[var(--border-secondary)] rounded px-3 py-2 text-xs text-[var(--text-primary)] placeholder:text-[var(--text-muted)]"
          />
        </div>
        <div>
          <label className="text-[10px] text-[var(--text-tertiary)] block mb-1">
            API 妯″瀷鍚?*锛堝彲涓庡唴缃噸澶嶏級
          </label>
          <input
            type="text"
            value={apiModel}
            onChange={(e) => setApiModel(e.target.value)}
            placeholder="濡傦細gpt-4-turbo銆乧laude-3-opus"
            className="w-full bg-[var(--bg-hover)] border border-[var(--border-secondary)] rounded px-3 py-2 text-xs text-[var(--text-primary)] placeholder:text-[var(--text-muted)] font-mono"
