  /**
   * 鍔犲叆鍏ㄥ眬璧勪骇搴擄紙閬撳叿锛塡n   */
  const handleAddPropToProjectLibrary = (prop: Prop) => {
    if (!seriesProject) {
      showAlert('鏃犳硶鑾峰彇椤圭洰淇℃伅锛岃鍒锋柊閲嶈瘯', { type: 'error' })
      return
    }

    const existingById = seriesProject.propLibrary.find(
      (p) => p.id === prop.libraryId
    )
    const existingByName = seriesProject.propLibrary.find(
      (p) => p.name === prop.name
    )
    const existing = existingById || existingByName

    const saveToLibrary = () => {
      try {
        let libraryPropId = existing?.id

        if (existing) {
          updatePropInLibrary({
            ...prop,
            id: existing.id,
            libraryId: undefined,
            libraryVersion: undefined
          })
        } else {
          const libProp: Prop = {
            ...prop,
            id:
              'prop_' +
              Date.now().toString(36) +
              '_' +
              Math.random().toString(36).slice(2, 6),
            libraryId: undefined,
            libraryVersion: undefined,
            version: 1
          }
          addPropToLibrary(libProp)
          libraryPropId = libProp.id
        }

        updateProject((prev) => {
          if (!prev.scriptData) return prev

          const newProps = prev.scriptData.props.map((p) => {
            if (p.id === prop.id && libraryPropId) {
              return {
                ...p,
                libraryId: libraryPropId,
                libraryVersion: existing ? (existing.version || 0) + 1 : 1
              }
            }
            return p
          })

          if (!libraryPropId)
            return {
              ...prev,
              scriptData: { ...prev.scriptData, props: newProps }
            }

          const nextRef: EpisodePropRef = {
            propId: libraryPropId,
            syncedVersion: existing ? (existing.version || 0) + 1 : 1,
            syncStatus: 'synced'
          }

          const newRefs = upsertEpisodeRef(
            prev.propRefs,
            libraryPropId,
            (r) => r.propId,
            nextRef
          )

          return {
            ...prev,
            scriptData: { ...prev.scriptData, props: newProps },
            propRefs: newRefs
          }
        })

        showAlert(`宸?{existing ? '鏇存柊' : '鍔犲叆'}椤圭洰閬撳叿搴擄細${prop.name}`, {
          type: 'success'
        })
      } catch (e: any) {
        showAlert(e?.message || '鍔犲叆椤圭洰閬撳叿搴撳け璐?, { type: 'error' })
      }
    }

    if (existing) {
      showAlert(
        `椤圭洰閬撳叿搴撲腑宸插瓨鍦ㄥ悕涓衡€?{existing.name}鈥濈殑閬撳叿锛屾槸鍚﹁鐩栨洿鏂帮紵`,
        {
          type: 'warning',
          showCancel: true,
          onConfirm: saveToLibrary
        }
      )
    } else {
      saveToLibrary()
    }
  }

