                width: `${(batchProgress.current / batchProgress.total) * 100}%`
              }}
            />
          </div>
          <p className="text-[var(--text-tertiary)] font-mono text-xs">
            杩涘害: {batchProgress.current} / {batchProgress.total}
          </p>
        </div>
      )}

      {/* Wardrobe Modal */}
      {selectedChar && (
        <WardrobeModal
          character={selectedChar}
