type SectionKey =
  | 'quality'
  | 'context'
  | 'keyframe'
  | 'narrative'
  | 'video'
  | 'advanced'

const ShotWorkbench: React.FC<ShotWorkbenchProps> = ({
  shot,
  shotIndex,
  totalShots,
  scriptData,
  currentVideoModelId,
  nextShotHasStartFrame = false,
  isAIOptimizing = false,
  isAIReassessing = false,
  isSplittingShot = false,
  onClose,
  onPrevious,
  onNext,
  onAIReassessQuality,
  onEditActionSummary,
  onEditDialogue,
  onGenerateAIAction,
  onSplitShot,
  onAddCharacter,
  onRemoveCharacter,
  onVariationChange,
  onSceneChange,
  onAddProp,
  onRemoveProp,
  onGenerateKeyframe,
  onUploadKeyframe,
  onEditKeyframePrompt,
  onOptimizeKeyframeWithAI,
  onOptimizeBothKeyframes,
  onCopyPreviousEndFrame,
  onCopyNextStartFrame,
  useAIEnhancement,
  onToggleAIEnhancement,
  onGenerateVideo,
  onGenerateDubbing,
  onClearDubbing,
  onEditVideoPrompt,
  onVideoModelChange,
  onImageClick,
  videoInputMode,
  onVideoInputModeChange,
  onGenerateNineGrid,
  nineGrid,
  onSelectNineGridPanel,
  onShowNineGrid
}) => {
  const scene = findSceneByIdCompat(scriptData?.scenes, shot.sceneId)
  const activeCharacters =
    scriptData?.characters.filter((c) => shot.characters.includes(c.id)) || []
  const availableCharacters =
    scriptData?.characters.filter((c) => !shot.characters.includes(c.id)) || []
  const activeProps = (scriptData?.props || []).filter((p) =>
    (shot.props || []).includes(p.id)
  )
  const availablePropsForShot = (scriptData?.props || []).filter(
    (p) => !(shot.props || []).includes(p.id)
  )

  const startKf = shot.keyframes?.find((k) => k.type === 'start')
  const endKf = shot.keyframes?.find((k) => k.type === 'end')
  const quality = shot.qualityAssessment
  const [localVideoModelId, setLocalVideoModelId] =
    useState(currentVideoModelId)
  const [expandedCheckKey, setExpandedCheckKey] = useState<string | null>(null)
  const [isAdvancedMode, setIsAdvancedMode] = useState(false)
  const [expandedSections, setExpandedSections] = useState<SectionKey[]>([
    'context'
  ])
  const lastAutoExpandedShotRef = useRef<string | null>(null)

  const isSectionOpen = (sectionKey: SectionKey) =>
    expandedSections.includes(sectionKey)
  const openSection = (sectionKey: SectionKey) => {
    setExpandedSections((prev) =>
      prev.includes(sectionKey) ? prev : [...prev, sectionKey]
    )
  }
  const toggleSection = (sectionKey: SectionKey) => {
    setExpandedSections((prev) =>
      prev.includes(sectionKey)
        ? prev.filter((item) => item !== sectionKey)
        : [...prev, sectionKey]
    )
  }

  useEffect(() => {
    setLocalVideoModelId(currentVideoModelId)
  }, [currentVideoModelId])

  const modelRouting = resolveVideoModelRouting(
    localVideoModelId || currentVideoModelId || 'sora-2'
  )
  const recommendedInputMode: 'keyframes' | 'storyboard-grid' =
    modelRouting.family === 'sora' || modelRouting.family === 'doubao-task'
      ? 'storyboard-grid'
      : 'keyframes'
  const effectiveVideoInputMode = videoInputMode || recommendedInputMode
  const resolveStoredGridPanelCount = (): StoryboardGridPanelCount | null => {
    const fromLayout = nineGrid?.layout?.panelCount
    if (fromLayout === 4 || fromLayout === 6 || fromLayout === 9) {
      return fromLayout
    }

    const panelLength = nineGrid?.panels?.length
    if (panelLength === 4 || panelLength === 6 || panelLength === 9) {
      return panelLength
    }

    return null
  }
  const resolveDefaultGridPanelCount = (): StoryboardGridPanelCount => {
    const intervalDuration = Number(shot.interval?.duration)
    if (Number.isFinite(intervalDuration) && intervalDuration === 8) {
      return 6
    }

    const modelId =
      localVideoModelId || currentVideoModelId || shot.videoModel || 'sora-2'
    const model = getModelById(modelId) as any
    const modelDefaultDuration = Number(model?.params?.defaultDuration)
    if (Number.isFinite(modelDefaultDuration) && modelDefaultDuration === 8) {
      return 6
    }

    return 9
  }
  const resolvePreferredGridPanelCount = (): StoryboardGridPanelCount =>
    resolveStoredGridPanelCount() ?? resolveDefaultGridPanelCount()
  const [selectedGridPanelCount, setSelectedGridPanelCount] =
    useState<StoryboardGridPanelCount>(() => resolvePreferredGridPanelCount())
  const selectedGridLayout = resolveStoryboardGridLayout(selectedGridPanelCount)
  const existingGridLayout = resolveStoryboardGridLayout(
    nineGrid?.layout?.panelCount,
    nineGrid?.panels?.length
  )
  const hasSameGridLayout =
    !!nineGrid?.panels?.length &&
    existingGridLayout.panelCount === selectedGridLayout.panelCount

  useEffect(() => {
    setSelectedGridPanelCount(resolvePreferredGridPanelCount())
  }, [shot.id, nineGrid?.layout?.panelCount, nineGrid?.panels?.length])

  const showEndFrame = modelRouting.supportsEndFrame
  const hasStartFrame = !!startKf?.imageUrl
  const hasEndFrame = !!endKf?.imageUrl
  const keyframeReady =
    effectiveVideoInputMode === 'storyboard-grid'
      ? hasStartFrame
      : hasStartFrame && (!showEndFrame || hasEndFrame)
  const hasActionSummary = (shot.actionSummary || '').trim().length > 0
  const hasVideo = !!shot.interval?.videoUrl
  const isVideoGenerating = shot.interval?.status === 'generating'

  useEffect(() => {
    if (lastAutoExpandedShotRef.current === shot.id) {
      return
    }
    lastAutoExpandedShotRef.current = shot.id

    if (!hasActionSummary) {
      openSection('narrative')
      return
    }
    if (!keyframeReady) {
      openSection('keyframe')
      return
    }
    if (!hasVideo) {
      openSection('video')
      return
    }
    openSection('quality')
  }, [shot.id, hasActionSummary, keyframeReady, hasVideo])

  useEffect(() => {
    setExpandedCheckKey(null)
  }, [shot.id])

  useEffect(() => {
    if (effectiveVideoInputMode === 'storyboard-grid') {
      setIsAdvancedMode(true)
    }
  }, [effectiveVideoInputMode])

  const qualityGradeLabel =
    quality?.grade === 'pass'
      ? '閫氳繃'
      : quality?.grade === 'warning'
        ? '闇€浼樺寲'
        : '楂橀闄?
  const qualityBadgeClass =
    quality?.grade === 'pass'
      ? 'bg-[var(--success-bg)] text-[var(--success-text)] border-[var(--success-border)]'
      : quality?.grade === 'warning'
        ? 'bg-[var(--warning-bg)] text-[var(--warning-text)] border-[var(--warning-border)]'
        : 'bg-[var(--error-hover-bg)] text-[var(--error-text)] border-[var(--error-border)]'
  const qualitySourceLabel = quality
    ? quality.version >= 2
      ? 'AI璇勪及 V2'
      : '瑙勫垯璇勫垎 V1'
    : ''

  const checkLabelMap: Record<string, string> = {
    'prompt-readiness': '鎻愮ず璇嶅畬鏁村害',
    'asset-coverage': '璧勪骇瑕嗙洊搴?,
    'keyframe-execution': '鍏抽敭甯у氨缁害',
    'video-execution': '瑙嗛鎵ц鐘舵€?,
    'continuity-risk': '杩炶疮鎬ч闄?
  }

  const adviceMap: Record<string, string> = {
    'prompt-readiness': '寤鸿鍏堣ˉ鍏ㄩ甯?灏惧抚/瑙嗛鎻愮ず璇嶏紝閬垮厤鎵ц姝т箟銆?,
    'asset-coverage': '寤鸿琛ヨ鑹?鍦烘櫙/閬撳叿鍙傝€冨浘锛屾彁楂橀鏍间竴鑷存€с€?,
    'keyframe-execution': '寤鸿鍏堝畬鎴愬叧閿抚鍑哄浘锛屽啀杩涘叆瑙嗛鐢熸垚銆?,
    'video-execution': '寤鸿浼樺厛瀹屾垚瑙嗛鐢熸垚骞剁‘璁ゅ彲鎾斁缁撴灉銆?,
    'continuity-risk': '寤鸿琛ラ綈棣栧熬閿氱偣锛岀‘淇濊法闀滃ご杩炶疮銆?
  }

  const getCheckLabel = (checkKey: string, fallback: string) =>
    checkLabelMap[checkKey] || fallback

  const qualitySummary = (() => {
    if (!quality) return ''
    const failedLabels = quality.checks
      .filter((check) => !check.passed)
      .map((check) => getCheckLabel(check.key, check.label))
    if (failedLabels.length === 0) return '鍙繘鍏ョ敓浜э紝鏍稿績妫€鏌ラ」宸查€氳繃銆?
    if (quality.grade === 'fail') return `椋庨櫓杈冮珮锛?{failedLabels.join('銆?)}`
    if (quality.grade === 'warning')
      return `闇€瑕佷紭鍖栵細${failedLabels.join('銆?)}`
    return `杞诲井闂锛?{failedLabels.join('銆?)}`
  })()

  const weakestCheck = quality?.checks?.length
    ? [...quality.checks].sort((a, b) => a.score - b.score)[0]
    : undefined
  const qualityActionHint = weakestCheck
    ? adviceMap[weakestCheck.key] || ''
    : ''

  const steps = useMemo(
    () => [
      {
        key: 'context' as const,
        label: '1 璧勪骇缁戝畾',
        done: !!scene && activeCharacters.length > 0
      },
      {
        key: 'narrative' as const,
        label: '2 鍔ㄤ綔鍙拌瘝',
        done: hasActionSummary
      },
      {
        key: 'keyframe' as const,
        label:
          effectiveVideoInputMode === 'storyboard-grid'
            ? '3 缃戞牸鍒嗛暅'
            : '3 鍏抽敭甯?,
        done: keyframeReady
      },
      { key: 'video' as const, label: '4 瑙嗛鐢熸垚', done: hasVideo }
    ],
    [
      scene,
      activeCharacters.length,
      keyframeReady,
      hasActionSummary,
      hasVideo,
      effectiveVideoInputMode
    ]
  )
  const completedSteps = steps.filter((item) => item.done).length
  const recommendationText =
    modelRouting.family === 'sora' || modelRouting.family === 'doubao-task'
      ? '褰撳墠妯″瀷鎺ㄨ崘缃戞牸鍒嗛暅'
      : modelRouting.family === 'veo-fast'
        ? '褰撳墠妯″瀷鏀寔缃戞牸鍒嗛暅涓庨灏惧抚'
        : '褰撳墠妯″瀷鍙寜闀滃ご闇€姹傞€夋嫨杈撳叆鏂瑰紡'
  const isGridGenerating =
    nineGrid?.status === 'generating_panels' ||
    nineGrid?.status === 'generating_image'
  const openOrGenerateGridStoryboard = () => {
    if (
      hasSameGridLayout &&
      (nineGrid?.status === 'completed' ||
        nineGrid?.status === 'panels_ready' ||
        nineGrid?.status === 'generating_image')
    ) {
      onShowNineGrid()
      return
    }
    onGenerateNineGrid(selectedGridPanelCount)
  }

  const primaryAction = useMemo(() => {
    if (!hasActionSummary) {
      return {
        label: '涓嬩竴姝ワ細瀹屽杽鍔ㄤ綔涓庡彴璇?,
        hint: '鍏抽敭甯т笌缃戞牸鍒嗛暅渚濊禆鍔ㄤ綔鎻忚堪锛屽缓璁厛琛ラ綈鍙欎簨鍐呭銆?,
        disabled: false,
        onClick: () => openSection('narrative')
      }
    }

    if (effectiveVideoInputMode === 'storyboard-grid' && !hasStartFrame) {
      return {
        label: '涓嬩竴姝ワ細鐢熸垚缃戞牸鍒嗛暅',
        hint: isAdvancedMode
          ? `鍏堢敓鎴?{selectedGridLayout.label}骞堕€夊畾棣栧抚锛屽啀杩涘叆瑙嗛鐢熸垚銆俙
          : '缃戞牸鍒嗛暅灞炰簬楂樼骇鍔熻兘锛岃鍏堝垏鎹㈠埌鈥滈珮绾р€濄€?,
        disabled: isGridGenerating,
        onClick: () => {
          openSection('keyframe')
          if (!isAdvancedMode) {
            setIsAdvancedMode(true)
            return
          }
          openOrGenerateGridStoryboard()
        }
      }
    }

    if (!hasStartFrame) {
      return {
        label: '涓嬩竴姝ワ細鐢熸垚棣栧抚',
        hint: '鍏堢敓鎴愰甯э紝寤虹珛闀滃ご瑙嗚閿氱偣銆?,
        disabled: startKf?.status === 'generating',
        onClick: () => {
          openSection('keyframe')
          onGenerateKeyframe('start')
        }
      }
    }

    if (
      effectiveVideoInputMode === 'keyframes' &&
      showEndFrame &&
      !hasEndFrame
    ) {
      return {
        label: '涓嬩竴姝ワ細鐢熸垚灏惧抚',
        hint: '琛ラ綈棣栧熬鍏抽敭甯у悗锛屽啀鍋氳棰戜細鏇寸ǔ瀹氥€?,
        disabled: endKf?.status === 'generating',
        onClick: () => {
          openSection('keyframe')
          onGenerateKeyframe('end')
        }
      }
    }

    if (!hasVideo) {
      return {
        label: isVideoGenerating ? '瑙嗛鐢熸垚涓?..' : '涓嬩竴姝ワ細杩涘叆瑙嗛鐢熸垚',
        hint: isVideoGenerating
          ? '褰撳墠闀滃ご姝ｅ湪鍑虹墖锛岃绋嶅€欍€?
          : '鍦ㄦ楠?4 閫夋嫨妯″瀷鍜屽弬鏁板悗鐢熸垚瑙嗛銆?,
        disabled: isVideoGenerating,
        onClick: () => openSection('video')
      }
    }

    return {
      label: isAIReassessing ? 'AI璇勪及涓?..' : '涓嬩竴姝ワ細AI閲嶈瘎浼?,
      hint: '瑙嗛宸插畬鎴愶紝寤鸿鍋氫竴娆℃渶缁堝彲浜や粯鎬ц瘎浼般€?,
      disabled: isAIReassessing,
      onClick: () => {
        openSection('quality')
        onAIReassessQuality()
      }
    }
  }, [
    hasActionSummary,
    effectiveVideoInputMode,
    hasStartFrame,
    isAdvancedMode,
    selectedGridLayout.label,
    selectedGridPanelCount,
    isGridGenerating,
    openOrGenerateGridStoryboard,
    startKf?.status,
    showEndFrame,
    hasEndFrame,
    endKf?.status,
    hasVideo,
    isVideoGenerating,
    isAIReassessing,
    onGenerateKeyframe,
    onAIReassessQuality
  ])

  const getShotDisplayNumber = () => {
    return getShotDisplayKey(shot.id, shotIndex)
  }

  const renderSectionHeader = (
    sectionKey: SectionKey,
    title: string,
    subtitle: string,
    done?: boolean
  ) => {
    const isOpen = isSectionOpen(sectionKey)
    return (
      <button
        type="button"
        className="w-full px-4 py-3 flex items-center justify-between text-left"
        onClick={() => toggleSection(sectionKey)}
      >
        <div className="flex items-center gap-2 min-w-0">
          {done === undefined ? null : done ? (
            <CheckCircle2 className="w-4 h-4 text-[var(--success-text)] shrink-0" />
          ) : (
            <Circle className="w-4 h-4 text-[var(--text-muted)] shrink-0" />
          )}
          <div className="min-w-0">
            <p className="text-xs font-bold text-[var(--text-secondary)] uppercase tracking-widest">
              {title}
            </p>
            <p className="text-[10px] text-[var(--text-muted)] truncate">
              {subtitle}
            </p>
          </div>
        </div>
        {isOpen ? (
          <ChevronUp className="w-4 h-4 text-[var(--text-muted)]" />
        ) : (
          <ChevronDown className="w-4 h-4 text-[var(--text-muted)]" />
        )}
      </button>
    )
  }

  return (
    <div className="w-[500px] bg-[var(--bg-deep)] flex flex-col h-full shadow-2xl animate-in slide-in-from-right-10 duration-300 relative z-20">
      <div className="h-16 px-6 border-b border-[var(--border-primary)] flex items-center justify-between bg-[var(--bg-surface)] shrink-0">
        <div className="flex items-center gap-3 min-w-0 flex-1 mr-2">
          <span className="min-w-[3rem] h-8 px-2 bg-[var(--accent-bg)] text-[var(--accent-text)] rounded-lg flex items-center justify-center font-bold font-mono text-[11px] whitespace-nowrap border border-[var(--accent-border)] shrink-0">
            {getShotDisplayNumber()}
          </span>
          <div className="min-w-0 flex-1">
            <h3 className="text-[var(--text-primary)] font-bold text-sm">
              闀滃ご璇︽儏
            </h3>
            <p
              className="text-[10px] text-[var(--text-tertiary)] uppercase tracking-widest truncate"
              title={shot.cameraMovement}
            >
              {shot.cameraMovement}
            </p>
          </div>
        </div>

        <div className="flex items-center gap-1">
          <div className="flex items-center rounded-md border border-[var(--border-primary)] bg-[var(--bg-base)]/40 mr-2">
            <button
              type="button"
              className={`px-2 py-1 text-[10px] font-medium ${!isAdvancedMode ? 'text-[var(--text-primary)] bg-[var(--bg-hover)]' : 'text-[var(--text-tertiary)]'}`}
              onClick={() => setIsAdvancedMode(false)}
              title="浠呮樉绀烘牳蹇冩祦绋嬶紝闄嶄綆澶嶆潅搴

w-3 h-3 animate-spin" />
                  ) : (
                    <Sparkles className="w-3 h-3" />
                  )}
                  {isAIReassessing ? '璇勪及涓?..' : 'AI閲嶈瘎浼?}
                </button>
              </div>
              <p className="text-xs text-[var(--text-secondary)]">
                {qualitySummary}
