  ): Shot => ({
    ...shot,
    qualityAssessment: assessShotQuality(shot, scriptData)
  })

  /**
   * 鍦烘櫙璐熼潰鎻愮ず璇嶉噷甯稿寘鍚€滅姝汉鐗┾€濈殑绾︽潫锛堢敤浜庣函鐜鍥撅級锛孿n   * 鍦ㄨ鑹查暅澶翠腑搴旂Щ闄よ繖浜涜瘝鏉★紝閬垮厤涓庘€滃繀椤诲嚭浜衡€濈洰鏍囧啿绐併€俓n   */
  const stripHumanExclusionTerms = (input?: string): string => {
    if (!input || typeof input !== 'string') return ''
    const humanBlockPatterns: RegExp[] = [
      /\bperson\b/i,
      /\bpeople\b/i,
      /\bhuman\b/i,
      /\bman\b/i,
      /\bwoman\b/i,
      /\bchild\b/i,
      /\bfigure\b/i,
      /\bsilhouette\b/i,
      /\bcrowd\b/i,
      /\bpedestrian\b/i,
      /\bcharacter\b/i
    ]

    return input
      .split(/[,;锛岋紱\n]+/)
      .map((item) => item.trim())
      .filter(Boolean)
      .filter(
        (item) => !humanBlockPatterns.some((pattern) => pattern.test(item))
      )
      .join(', ')
  }

  const formatUserFriendlyError = (error: any, fallback: string): string => {
    if (!error) return fallback

    const status = error?.status
    const rawMessage = typeof error?.message === 'string' ? error.message : ''
    const moderationMessage = toFriendlyModerationMessage(rawMessage, {
      includeUnknownReasonCode: import.meta.env.DEV
    })

    let normalizedMessage = moderationMessage || rawMessage
    if (!normalizedMessage) {
      if (status === 400) {
        normalizedMessage = '鎻愮ず璇嶅彲鑳借椋庢帶鎷︽埅锛岃淇敼鎻愮ず璇嶅悗閲嶈瘯銆?
      } else if (status === 500 || status === 503) {
        normalizedMessage = '鏈嶅姟鍣ㄧ箒蹇欙紝璇风◢鍚庨噸璇曘€?
      } else {
        normalizedMessage = fallback
      }
    }

    if (!import.meta.env.DEV) {
      normalizedMessage = normalizedMessage.replace(/锛堟帴鍙ｄ俊鎭細.*?锛?g, '')
    }

    return normalizedMessage || fallback
  }

  const buildShotNegativePrompt = (shot: Shot, visualStyle: string): string => {
    const parts: string[] = []
    const shotHasCharacters = (shot.characters?.length || 0) > 0
    const pushPrompt = (value?: string) => {
      if (!value || typeof value !== 'string') return
      const trimmed = value.trim()
      if (trimmed) parts.push(trimmed)
    }

    pushPrompt(getNegativePrompt(visualStyle))

    const scriptData = project.scriptData
    if (!scriptData) {
      return parts.join(', ')
    }

    const scene = findSceneByIdCompat(scriptData.scenes, shot.sceneId)
    pushPrompt(
      shotHasCharacters
        ? stripHumanExclusionTerms(scene?.negativePrompt)
        : scene?.negativePrompt
    )

    if (shot.characters?.length) {
      shot.characters.forEach((charId) => {
        const char = scriptData.characters.find(
          (c) => String(c.id) === String(charId)
        )
        if (!char) return
        const variationId = shot.characterVariations?.[charId]
        const variation = variationId
          ? char.variations?.find((v) => v.id === variationId)
          : undefined
        pushPrompt(variation?.negativePrompt || char.negativePrompt)
      })
    }

    if (shot.props?.length && scriptData.props) {
      shot.props.forEach((propId) => {
        const prop = scriptData.props?.find(
          (p) => String(p.id) === String(propId)
        )
        pushPrompt(prop?.negativePrompt)
      })
    }

    const deduped: string[] = []
    const seen = new Set<string>()
    parts
      .flatMap((part) => part.split(/[,;锛岋紱\n]+/))
      .map((item) => item.trim())
      .filter(Boolean)
      .forEach((item) => {
        const key = item.toLowerCase()
        if (seen.has(key)) return
        seen.add(key)
        deduped.push(item)
      })

    return deduped.slice(0, 80).join(', ')
  }

  const allStartFramesGenerated =
    project.shots.length > 0 &&
    project.shots.every(
      (s) => s.keyframes?.find((k) => k.type === 'start')?.imageUrl
    )

  /**
   * 缁勪欢鍔犺浇鏃讹紝妫€娴嬪苟閲嶇疆鍗′綇鐨勭敓鎴愮姸鎬乗n   * 瑙ｅ喅鍏抽棴绯荤粺鍚庨噸鏂版墦寮€鏃讹紝鐘舵€佷粛涓篭

瀵艰嚧鏃犳硶閲嶆柊鐢熸垚鐨勯棶棰榎n   */
  useEffect(() => {
