                  ? { ...kf, status: 'failed' as const }
                  : kf
              ),
              interval:
                shot.interval && shot.interval.status === 'generating'
                  ? { ...shot.interval, status: 'failed' as const }
                  : shot.interval,
              dubbing:
                shot.dubbing && shot.dubbing.status === 'generating'
                  ? {
                      ...shot.dubbing,
                      status: 'failed' as const,
                      error: '浠诲姟涓柇锛岃閲嶆柊鐢熸垚'
                    }
                  : shot.dubbing,
              nineGrid:
                shot.nineGrid &&
                (shot.nineGrid.status === 'generating_panels' ||
                  shot.nineGrid.status === 'generating_image' ||
                  (shot.nineGrid.status as string) === 'generating')
                  ? { ...shot.nineGrid, status: 'failed' as const }
                  : shot.nineGrid
            },
            prevProject.scriptData
          )
        )
      }))
    }
  }, []) // 杩涘叆瀵兼紨椤垫椂鎵ц涓€娆★紝娓呯悊绂诲紑椤甸潰鍚庨仐鐣欑殑 generating 鐘舵€乗n
  /**
   * 涓婃姤鐢熸垚鐘舵€佺粰鐖剁粍浠讹紝鐢ㄤ簬瀵艰埅閿佸畾
   * 妫€娴嬫墍鏈夊彲鑳界殑鐢熸垚涓姸鎬侊細鎵归噺鐢熸垚銆佸崟涓叧閿抚銆佽棰戙€佷節瀹牸銆侀暅澶存媶鍒哱n   */
  useEffect(() => {
    const hasGeneratingKeyframes = project.shots.some((shot) =>
      shot.keyframes?.some((kf) => kf.status === 'generating')
