    const generating =
      !!batchProgress ||
      hasGeneratingKeyframes ||
      hasGeneratingVideo ||
      hasGeneratingDubbing ||
      hasGeneratingNineGrid ||
      isSplittingShot
    onGeneratingChange?.(generating)
  }, [batchProgress, project.shots, isSplittingShot])

  // 缁勪欢鍗歌浇鏃堕噸缃敓鎴愮姸鎬乗n  useEffect(() => {
    return () => {
      onGeneratingChange?.(false)
