  /**
   * 鐢熸垚鍏抽敭甯n   */
  const handleGenerateKeyframe = async (shot: Shot, type: 'start' | 'end') => {
    const existingKf = shot.keyframes?.find((k) => k.type === type)
    const kfId = existingKf?.id || generateId(`kf-${shot.id}-${type}`)
    const startKf = shot.keyframes?.find((k) => k.type === 'start')

    const rawBasePrompt = existingKf?.visualPrompt
      ? extractBasePrompt(existingKf.visualPrompt, shot.actionSummary)
      : shot.actionSummary

    const continuityHint =
      type === 'end' && startKf?.visualPrompt
        ? `銆愯繛璐€х害鏉熴€戠粨鏉熷抚蹇呴』涓庤捣濮嬪抚淇濇寔鍚屼竴瑙掕壊韬唤銆佹湇瑁呬富浣撱€佸満鏅敋鐐逛笌鍏夌収閫昏緫锛屽苟鍦ㄦ瀯鍥惧拰鍔ㄤ綔缁撴灉涓婁綋鐜版槑纭彉鍖栥€傝捣濮嬪抚鍙傝€冿細${extractBasePrompt(startKf.visualPrompt, shot.actionSummary).slice(0, 200)}`
        : ''

    const basePrompt =
      continuityHint && !rawBasePrompt.includes('銆愯繛璐€х害鏉熴€?)
        ? `${rawBasePrompt}\n\n${continuityHint}`
        : rawBasePrompt

    const visualStyle =
      project.visualStyle || project.scriptData?.visualStyle || '3d-animation'
    const negativePrompt = buildShotNegativePrompt(shot, visualStyle)

    // 鑾峰彇閬撳叿淇℃伅鐢ㄤ簬鎻愮ず璇嶆敞鍏n    const propsInfo = getPropsInfoForShot(shot, project.scriptData)

    // 鏍规嵁寮€鍏抽€夋嫨鏄惁浣跨敤AI澧炲己
    let prompt: string
    if (useAIEnhancement) {
      try {
        prompt = await buildKeyframePromptWithAI(
          basePrompt,
          visualStyle,
          shot.cameraMovement,
          type,
          true,
          propsInfo,
          promptTemplates
        )
      } catch (error) {
        console.error('AI澧炲己澶辫触,浣跨敤鍩虹鎻愮ず璇?', error)
        prompt = buildKeyframePrompt(
          basePrompt,
          visualStyle,
          shot.cameraMovement,
          type,
          propsInfo,
          promptTemplates
        )
      }
    } else {
      prompt = buildKeyframePrompt(
        basePrompt,
        visualStyle,
        shot.cameraMovement,
        type,
        propsInfo,
        promptTemplates
      )
    }

    const refResult = getRefImagesForShot(shot, project.scriptData)
    const referenceImages = [...refResult.images]
    const continuityReferenceImage =
      type === 'end' &&
      startKf?.imageUrl &&
      !referenceImages.includes(startKf.imageUrl)
        ? startKf.imageUrl
        : undefined
    const dedupedReferenceCount = new Set(
      [...referenceImages, continuityReferenceImage]
        .filter((img): img is string => !!img)
        .map((img) => img.trim())
        .filter(Boolean)
    ).size
    const effectiveReferenceCount = Math.min(5, dedupedReferenceCount)
    if (dedupedReferenceCount > 5) {
      const limitNote = continuityReferenceImage ? '锛堝惈杩炶疮鎬у弬鑰冨浘锛? : ''
      setToastMessage(
        `鍙傝€冨浘鏁伴噺 ${dedupedReferenceCount} 瓒呰繃妯″瀷涓婇檺锛屽凡鑷姩闄愬埗涓?5 寮?{limitNote}銆俙
      )
    }

    const activeImageModel = getActiveImageModel() as any
    const preflightResult = runKeyframePreflight({
      prompt,
      negativePrompt,
      hasCharacters: (shot.characters?.length || 0) > 0,
      frameType: type,
      hasStartFrameImage: !!startKf?.imageUrl,
      referenceImageCount: effectiveReferenceCount,
      aspectRatio: keyframeAspectRatio,
      supportedAspectRatios: activeImageModel?.params?.supportedAspectRatios
    })

    if (!preflightResult.canProceed) {
      showAlert(
        `鍏抽敭甯ч妫€鏈€氳繃锛歕
${formatLintIssues(preflightResult.issues)}`,
        { type: 'warning' }
      )
      return
    }

    const nonErrorIssues = preflightResult.issues.filter(
      (issue) => issue.severity !== 'error'
    )
    if (nonErrorIssues.length > 0) {
      setToastMessage(`鍏抽敭甯ч妫€鎻愰啋锛歕
${formatLintIssues(nonErrorIssues)}`)
    }

    const promptVersions = updatePromptWithVersion(
      existingKf?.visualPrompt,
      prompt,
      existingKf?.promptVersions,
      'ai-generated',
      `Generate ${type} keyframe`
    )

    // 绔嬪嵆璁剧疆鐢熸垚鐘舵€侊紝鏄剧ずloading
    updateShot(shot.id, (s) => {
      const generatingKeyframe = {
        ...createKeyframe(kfId, type, prompt, undefined, 'generating'),
        promptVersions
      }
      return updateKeyframeInShot(s, type, generatingKeyframe)
    })

    try {
      // 浣跨敤褰撳墠璁剧疆鐨勬í绔栧睆姣斾緥鐢熸垚鍏抽敭甯э紝浼犻€?hasTurnaround 鏍囪
      const url = await generateImage(
        prompt,
        referenceImages,
        keyframeAspectRatio,
        false,
        refResult.hasTurnaround,
        negativePrompt,
        continuityReferenceImage
          ? { continuityReferenceImage, referencePackType: 'shot' }
          : { referencePackType: 'shot' }
      )

      updateShot(shot.id, (s) => {
        const completedKeyframe = {
          ...createKeyframe(kfId, type, prompt, url, 'completed'),
          promptVersions
        }
        return updateKeyframeInShot(s, type, completedKeyframe)
      })
    } catch (e: any) {
      console.error(e)
      updateShot(shot.id, (s) => {
        const failedKeyframe = {
          ...createKeyframe(kfId, type, prompt, undefined, 'failed'),
          promptVersions
        }
        return updateKeyframeInShot(s, type, failedKeyframe)
      })

      if (onApiKeyError && onApiKeyError(e)) return
      showAlert(
        `鐢熸垚澶辫触: ${formatUserFriendlyError(e, '鍥剧墖鐢熸垚澶辫触锛岃绋嶅悗閲嶈瘯銆?)}`,
        { type: 'error' }
      )
    }
  }

  /**
   * 涓婁紶鍏抽敭甯у浘鐗嘰n   */
  const handleUploadKeyframeImage = async (
    shot: Shot,
    type: 'start' | 'end'
  ) => {
    const input = document.createElement('input')
    input.type = 'file'
    input.accept = 'image/*'

    input.onchange = async (e: any) => {
      const file = e.target.files?.[0]
      if (!file) return

      if (!file.type.startsWith('image/')) {
        showAlert('璇烽€夋嫨鍥剧墖鏂囦欢锛?, { type: 'warning' })
        return
      }

      try {
        const base64Url = await convertImageToBase64(file)
        const existingKf = shot.keyframes?.find((k) => k.type === type)
        const kfId = existingKf?.id || generateId(`kf-${shot.id}-${type}`)

        updateShot(shot.id, (s) => {
          const visualPrompt = existingKf?.visualPrompt || shot.actionSummary
          const uploadedKeyframe = {
            ...createKeyframe(kfId, type, visualPrompt, base64Url, 'completed'),
            promptVersions: existingKf?.promptVersions
          }
          return updateKeyframeInShot(s, type, uploadedKeyframe)
        })
      } catch (error) {
        showAlert('璇诲彇鏂囦欢澶辫触锛?, { type: 'error' })
      }
    }

    input.click()
  }

  /**
   * 鐢熸垚瑙嗛
   * @param shot - 闀滃ご鏁版嵁
   * @param aspectRatio - 妯珫灞忔瘮渚媆n   * @param duration - 瑙嗛鏃堕暱锛堜粎寮傛妯″瀷鏈夋晥锛塡n   * @param modelId - 瑙嗛妯″瀷 ID
   */
  const handleGenerateVideo = async (
    shot: Shot,
    aspectRatio: AspectRatio = '16:9',
    duration: VideoDuration = 8,
    modelId?: string
  ) => {
    const sKf = shot.keyframes?.find((k) => k.type === 'start')
    const eKf = shot.keyframes?.find((k) => k.type === 'end')

    // 浣跨敤浼犲叆鐨?modelId 鎴栭粯璁ゆā鍨媆n    const selectedModelInput: string =
      modelId || shot.videoModel || DEFAULTS.videoModel
    const selectedModelRouting = resolveVideoModelRouting(selectedModelInput)
    const selectedModel = selectedModelRouting.normalizedModelId
    // 瑙勮寖鍖栨ā鍨嬪悕绉帮細鏃фā鍨嬪悕 -> 鐜拌鍙敤妯″瀷

    // 蹇呴』鏈夎捣濮嬪抚
    if (!sKf?.imageUrl) {
      return showAlert('璇峰厛鐢熸垚璧峰甯э紒', { type: 'warning' })
    }

    const projectLanguage =
      project.language || project.scriptData?.language || '涓枃'
    const visualStyle =
      project.visualStyle || project.scriptData?.visualStyle || 'live-action'

    const videoInputMode =
      shot.videoInputMode || getRecommendedVideoInputMode(selectedModel)
    // 妫€娴嬫槸鍚︿负缃戞牸鍒嗛暅妯″紡锛氬繀椤绘樉寮忛€夋嫨缃戞牸妯″紡 + 棣栧抚浣跨敤鏁村紶缃戞牸鍥綷n    const isNineGridMode =
      videoInputMode === 'storyboard-grid' &&
      shot.nineGrid?.status === 'completed' &&
      shot.nineGrid?.imageUrl &&
      sKf?.imageUrl === shot.nineGrid.imageUrl

    const routedFrames = routeVideoFrameInputs(
      selectedModel,
      sKf?.imageUrl,
      eKf?.imageUrl,
      videoInputMode
    )
    const routedEndKeyframeId = routedFrames.endImage ? eKf?.id || '' : ''

    if (routedFrames.ignoredEndFrame) {
      if (videoInputMode === 'storyboard-grid' && !!eKf?.imageUrl) {
        setToastMessage(
          '缃戞牸鍒嗛暅妯″紡宸插惎鐢細瑙嗛鐢熸垚灏嗗彧浣跨敤棣栧抚锛屽熬甯ц緭鍏ュ凡鑷姩蹇界暐銆?
        )
      } else {
        const modelName =
          selectedModelRouting.family === 'sora'
            ? 'Sora'
            : selectedModelRouting.family === 'doubao-task'
              ? 'Doubao Task'
              : selectedModel
        setToastMessage(
          `鑳藉姏璺敱锛?{modelName} 褰撳墠鍙娇鐢ㄩ甯э紝宸茶嚜鍔ㄥ拷鐣ュ熬甯ц緭鍏ャ€俙
        )
      }
    }

    let videoPrompt = (shot.interval?.videoPrompt || '').trim()
    if (!videoPrompt) {
      videoPrompt = buildVideoPrompt(
        shot.actionSummary,
        shot.cameraMovement,
        selectedModel,
        projectLanguage,
        visualStyle,
        isNineGridMode ? shot.nineGrid : undefined,
        duration,
        {
          hasStartFrame: !!routedFrames.startImage,
          hasEndFrame: !!routedFrames.endImage
        },
        promptTemplates
      )
    }
    if (isNineGridMode) {
      const panelCountForGuard =
        shot.nineGrid?.layout?.panelCount || shot.nineGrid?.panels?.length || 9
      videoPrompt = ensureNineGridVideoPromptGuardrails(
        videoPrompt,
        panelCountForGuard,
        projectLanguage,
        promptTemplates
      )
    }

    const videoPromptLength = Array.from(videoPrompt).length
    if (videoPromptLength > 5000) {
      const compressionResult = await compressPromptWithLLM({
        text: videoPrompt,
        maxChars: 4920,
        mode: 'video',
        timeoutMs: 45000
      })
      if (compressionResult.compressed) {
        videoPrompt = compressionResult.text
        setToastMessage(
          `Video prompt compressed by ${compressionResult.model}: ` +
            `${compressionResult.originalLength} -> ${compressionResult.finalLength} chars`
        )
      }
    }

    const selectedModelConfig = (getModelById(selectedModelInput) ||
      getModelById(selectedModel)) as any
    const preflightResult = runVideoPreflight({
      prompt: videoPrompt,
      hasStartFrame: !!routedFrames.startImage,
      hasEndFrame: !!routedFrames.endImage,
      modelId: selectedModel,
      supportsEndFrame: selectedModelRouting.supportsEndFrame,
      aspectRatio,
      supportedAspectRatios: selectedModelConfig?.params?.supportedAspectRatios,
      duration,
      supportedDurations: selectedModelConfig?.params?.supportedDurations
    })

    if (!preflightResult.canProceed) {
      showAlert(
        `瑙嗛棰勬鏈€氳繃锛歕
${formatLintIssues(preflightResult.issues)}`,
        { type: 'warning' }
      )
      return
    }

    const nonErrorIssues = preflightResult.issues.filter(
      (issue) => issue.severity !== 'error'
    )
    if (nonErrorIssues.length > 0) {
      setToastMessage(`瑙嗛棰勬鎻愰啋锛歕
${formatLintIssues(nonErrorIssues)}`)
    }

    const intervalId = shot.interval?.id || generateId(`int-${shot.id}`)
    const intervalPromptVersions = updatePromptWithVersion(
      shot.interval?.videoPrompt,
      videoPrompt,
      shot.interval?.promptVersions,
      'ai-generated',
      `Generate video (${selectedModel})`
    )

    // 鏇存柊 shot 鐨?videoModel
    updateShot(shot.id, (s) => ({
      ...s,
      videoModel: selectedModel as any,
      interval: s.interval
        ? {
            ...s.interval,
            status: 'generating',
            videoPrompt,
            promptVersions: intervalPromptVersions
          }
        : {
            id: intervalId,
            startKeyframeId: sKf?.id || '',
            endKeyframeId: routedEndKeyframeId,
            duration: duration,
            motionStrength: 5,
            videoPrompt,
            promptVersions: intervalPromptVersions,
            status: 'generating'
          }
    }))

    try {
      const videoUrl = await generateVideo(
        videoPrompt,
        routedFrames.startImage,
        routedFrames.endImage,
        selectedModel,
        aspectRatio,
        duration
      )
      const persistedVideoUrl = await persistVideoReference(videoUrl, {
        projectId: project.projectId || project.id,
        episodeId: project.id,
        shotId: shot.id
      })

      updateShot(shot.id, (s) => ({
        ...s,
        interval: s.interval
          ? {
              ...s.interval,
              videoUrl: persistedVideoUrl,
              status: 'completed',
              promptVersions: intervalPromptVersions
            }
          : {
              id: intervalId,
              startKeyframeId: sKf?.id || '',
              endKeyframeId: routedEndKeyframeId,
              duration: duration,
              motionStrength: 5,
              videoPrompt,
              promptVersions: intervalPromptVersions,
              videoUrl: persistedVideoUrl,
              status: 'completed'
            }
      }))
    } catch (e: any) {
      console.error(e)
      updateShot(shot.id, (s) => ({
        ...s,
        interval: s.interval
          ? {
              ...s.interval,
              status: 'failed',
              promptVersions: intervalPromptVersions
            }
          : {
              id: intervalId,
              startKeyframeId: sKf?.id || '',
              endKeyframeId: routedEndKeyframeId,
              duration: duration,
              motionStrength: 5,
              videoPrompt,
              promptVersions: intervalPromptVersions,
              status: 'failed'
            }
      }))

      if (onApiKeyError && onApiKeyError(e)) return
      showAlert(`瑙嗛鐢熸垚澶辫触: ${formatUserFriendlyError(e, '璇风◢鍚庨噸璇曘€?)}`, {
        type: 'error'
      })
    }
  }

  /**
   * 鐢熸垚闀滃ご閰嶉煶锛堟梺鐧?/ 瀵硅瘽锛塡n   */
  const handleGenerateDubbing = async (
    shot: Shot,
    mode: DubbingMode,
    text: string,
    modelId?: string
  ) => {
    const cleanText = (text || '').trim()
