export const buildKeyframePromptWithAI = async (
  basePrompt: string,
  visualStyle: string,
  cameraMovement: string,
  frameType: 'start' | 'end',
  enhanceWithAI: boolean = true,
  propsInfo?: { name: string; description: string; hasImage: boolean }[],
  promptTemplates?: PromptTemplateConfig
): Promise<string> => {
  // 鍏堟瀯寤哄熀纭€鎻愮ず璇峔n  const basicPrompt = buildKeyframePrompt(
    basePrompt,
    visualStyle,
    cameraMovement,
    frameType,
    propsInfo,
    promptTemplates
  )

  // 濡傛灉涓嶉渶瑕丄I澧炲己,鐩存帴杩斿洖鍩虹鎻愮ず璇峔n  if (!enhanceWithAI) {
    return basicPrompt
  }

  // Use direct import from aiService; keep fallback behavior if enhancement fails.
  try {
    const enhanced = await enhanceKeyframePrompt(
      basicPrompt,
      visualStyle,
      cameraMovement,
      frameType,
      undefined,
      promptTemplates
