      }
    })
  }

  return {
    id: subShotId,
    sceneId: originalShot.sceneId, // 缁ф壙鍘熼暅澶寸殑鍦烘櫙ID
    actionSummary: subShotData.actionSummary, // 浣跨敤AI鐢熸垚鐨勫姩浣滄弿杩癨n    dialogue: undefined, // 涓嶇户鎵垮鐧?- 瀵圭櫧閫氬父鍙湪鐗瑰畾瀛愰暅澶翠腑鍑虹幇锛岀敱AI鍦╝ctionSummary涓綋鐜癨n    cameraMovement: subShotData.cameraMovement, // 浣跨敤AI鐢熸垚鐨勯暅澶磋繍鍔╘n    shotSize: subShotData.shotSize, // 浣跨敤AI鐢熸垚鐨勬櫙鍒玕n    characters: [...originalShot.characters], // 缁ф壙瑙掕壊鍒楄〃
    characterVariations: { ...originalShot.characterVariations }, // 缁ф壙瑙掕壊鍙樹綋鏄犲皠
    keyframes: keyframes, // 浣跨敤AI鐢熸垚鐨勫叧閿抚锛堝寘鍚玽isualPrompt锛塡n    videoModel: originalShot.videoModel // 缁ф壙瑙嗛妯″瀷璁剧疆
  }
}

/**
 * 鐢ㄥ瓙闀滃ご鏁扮粍鏇挎崲鍘熼暅澶碶n * @param shots - 鍘熷闀滃ご鏁扮粍
