  if (propsInfo && propsInfo.length > 0) {
    const propsWithImage = propsInfo.filter((p) => p.hasImage)
    const propsWithoutImage = propsInfo.filter((p) => !p.hasImage)

    const sections: string[] = []

    if (propsWithImage.length > 0) {
