    propConsistencyGuide = `

鈹佲攣鈹佲攣鈹佲攣鈹佲攣鈹佲攣鈹佲攣鈹佲攣鈹佲攣鈹佲攣鈹佲攣鈹佲攣鈹佲攣鈹佲攣鈹佲攣鈹佲攣鈹佲攣鈹佲攣
銆愰亾鍏蜂竴鑷存€ц姹傘€慞ROP CONSISTENCY REQUIREMENTS
${sections.join('\n\n')}`
  }

  return `${panel.description}${KEYFRAME_META_SPLITTER}

