${characterConsistencyGuide}${propConsistencyGuide}`
}

/**
 * 浠庣綉鏍煎垎闀滃浘涓鍓嚭鎸囧畾闈㈡澘鐨勫浘鐗嘰n * 鏀寔 2x2 / 3x2 / 3x3 缃戞牸甯冨眬
 * @param nineGridImageUrl - 缃戞牸鏁村浘 (base64)
 * @param panelIndex - 闈㈡澘绱㈠紩 (0-(panelCount-1))
 * @param layout - 缃戞牸甯冨眬锛堝彲閫夛紝榛樿鎸?3x3 鍏煎锛塡n * @returns 瑁佸壀鍚庣殑 base64 鍥剧墖
 */
export const cropPanelFromNineGrid = (
  nineGridImageUrl: string,
  panelIndex: number,
  layout?: NineGridData['layout']
): Promise<string> => {
  return new Promise((resolve, reject) => {
    const img = new Image()
    img.onload = () => {
      try {
        const resolvedLayout = resolveStoryboardGridLayout(
          layout?.panelCount,
          layout?.panelCount
        )
        if (panelIndex < 0 || panelIndex >= resolvedLayout.panelCount) {
          reject(new Error(`闈㈡澘绱㈠紩瓒婄晫: ${panelIndex}`))
          return
        }

        const canvas = document.createElement('canvas')
        const ctx = canvas.getContext('2d')
        if (!ctx) {
          reject(new Error('鏃犳硶鍒涘缓 Canvas 涓婁笅鏂?))
          return
        }

        // 璁＄畻瑁佸壀鍖哄煙锛氬姩鎬佺綉鏍硷紙2x2 / 3x2 / 3x3锛塡n        const col = panelIndex % resolvedLayout.cols
        const row = Math.floor(panelIndex / resolvedLayout.cols)

        const panelWidth = img.width / resolvedLayout.cols
        const panelHeight = img.height / resolvedLayout.rows

        const sx = col * panelWidth
        const sy = row * panelHeight

        // 璁剧疆杈撳嚭 canvas 灏哄涓哄崟涓潰鏉垮ぇ灏廫n        canvas.width = Math.round(panelWidth)
        canvas.height = Math.round(panelHeight)

        // 瑁佸壀骞剁粯鍒禱n        ctx.drawImage(
          img,
          Math.round(sx),
          Math.round(sy), // 婧愬潗鏍嘰n          Math.round(panelWidth),
          Math.round(panelHeight), // 婧愬昂瀵竆n          0,
          0, // 鐩爣鍧愭爣
          canvas.width,
          canvas.height // 鐩爣灏哄
        )

        // 杞崲涓?base64
        const croppedBase64 = canvas.toDataURL('image/png')
        resolve(croppedBase64)
      } catch (err) {
        reject(err)
      }
    }
    img.onerror = () => {
      reject(new Error('缃戞牸鍒嗛暅鍥剧墖鍔犺浇澶辫触'))
    }
    img.src = nineGridImageUrl
  })
}

