  const handleContinueScript = async () => {
    const finalModel = getFinalValue(localModel, customModelInput)
    const baseScript = localScript
    const separator = baseScript.trim() ? '\n\n' : ''
    const continueBudget =
      SCRIPT_HARD_LIMIT - baseScript.length - separator.length

    if (!baseScript.trim()) {
      setError('璇峰厛杈撳叆涓€浜涘墽鏈唴瀹逛綔涓哄熀纭€銆?)
      return
    }
    if (!finalModel) {
      setError('璇烽€夋嫨鎴栬緭鍏ユā鍨嬪悕绉般€?)
      return
    }
    if (continueBudget <= 0) {
      const message = `褰撳墠鍓ф湰宸茶揪鍒板崟闆嗕笂闄?${SCRIPT_HARD_LIMIT} 瀛楃锛屾棤娉曠户缁画鍐欙紝璇峰厛鎷嗗垎涓哄闆嗐€俙
      setError(message)
      showAlert(message, { type: 'warning' })
      return
    }

    setIsContinuing(true)
    setProcessingMessage('AI缁啓涓?..')
    setProcessingLogs([])
    setError(null)
    let streamed = ''
    let wasTruncated = false
    try {
      const continuedContent = await continueScriptStream(
        baseScript,
        localLanguage,
        finalModel,
        (delta) => {
          const remaining = continueBudget - streamed.length
          if (remaining <= 0) {
            wasTruncated = true
            return
          }
          const safeDelta = delta.slice(0, remaining)
          if (!safeDelta) {
            wasTruncated = true
            return
          }
          streamed += safeDelta
          const newScript = `${baseScript}${separator}${streamed}`
          setLocalScript(newScript)
          updateProject({ rawScript: newScript })
        },
        {
          maxAppendChars: continueBudget,
          maxTotalChars: SCRIPT_HARD_LIMIT
        }
      )
      if (continuedContent) {
        const safeContent = continuedContent.slice(0, continueBudget)
        if (safeContent.length < continuedContent.length) {
          wasTruncated = true
        }
        const newScript = `${baseScript}${separator}${safeContent}`
        setLocalScript(newScript)
        updateProject({ rawScript: newScript })
      }
      if (wasTruncated) {
        showAlert(
          `缁啓鍐呭宸叉寜鍗曢泦涓婇檺鑷姩鎴柇锛堟渶澶ф€婚暱 ${SCRIPT_HARD_LIMIT} 瀛楃锛夈€俙,
          { type: 'warning' }
        )
      }
    } catch (err: any) {
      console.error(err)
      setError(`AI缁啓澶辫触: ${err.message || '杩炴帴澶辫触'}`)
      try {
        const continuedContent = await continueScript(
          baseScript,
          localLanguage,
          finalModel,
          {
            maxAppendChars: continueBudget,
            maxTotalChars: SCRIPT_HARD_LIMIT
          }
        )
        const safeContent = continuedContent.slice(0, continueBudget)
        if (safeContent.length < continuedContent.length) {
          showAlert(
            `缁啓鍐呭宸叉寜鍗曢泦涓婇檺鑷姩鎴柇锛堟渶澶ф€婚暱 ${SCRIPT_HARD_LIMIT} 瀛楃锛夈€俙,
            { type: 'warning' }
          )
        }
        const newScript = `${baseScript}${separator}${safeContent}`
        setLocalScript(newScript)
        updateProject({ rawScript: newScript })
      } catch (fallbackErr: any) {
        console.error(fallbackErr)
      }
    } finally {
      setIsContinuing(false)
      setProcessingMessage('')
    }
  }

  const handleRewriteScript = async () => {
    const finalModel = getFinalValue(localModel, customModelInput)
    const baseScript = localScript

    if (!baseScript.trim()) {
      setError('璇峰厛杈撳叆鍓ф湰鍐呭銆?)
