  const handleAddSubShot = (anchorShotId: string) => {
    const anchorShot = project.shots.find((s) => s.id === anchorShotId)
    if (!anchorShot) return

    const newId = getNextSubShotId(
      anchorShotId,
      project.shots.map((shot) => shot.id)
    )
    if (!newId) return

    const groupPrefix = getShotGroupPrefix(anchorShotId)
    const baseShot =
      project.shots.find((shot) => shot.id === groupPrefix) || anchorShot
    const newShot: Shot = {
      id: newId,
      sceneId: baseShot.sceneId,
      actionSummary: '鍦ㄦ杈撳叆鍔ㄤ綔鎻忚堪',
      cameraMovement: baseShot.cameraMovement || '骞崇Щ',
