const normalizeChecks = (
  rawChecks: LLMRawCheck[] | undefined
): QualityCheck[] => {
  const rawMap = new Map<string, LLMRawCheck>()
  ;(rawChecks || []).forEach((check) => {
    if (typeof check.key === 'string' && check.key.trim()) {
      rawMap.set(check.key.trim(), check)
    }
  })

  return CHECK_DEFINITIONS.map((definition) => {
    const raw = rawMap.get(definition.key)
    const score = toSafeScore(raw?.score, 50)
    const passed = typeof raw?.passed === 'boolean' ? raw.passed : score >= 70
    const details =
      truncateText(raw?.details, 420) || '淇℃伅涓嶈冻锛屾ā鍨嬫湭杩斿洖璇︾粏渚濇嵁銆?
    return {
      key: definition.key,
      label: definition.label,
      weight: definition.weight,
      score,
      passed,
      details
    }
  })
}

const fallbackAssessment = (
  shot: Shot,
  scriptData?: ScriptData | null,
  reason?: string
): ShotQualityAssessment => {
  const base = assessShotQuality(shot, scriptData)
  const reasonMessage = truncateText(reason, 120)
  return {
    ...base,
    summary: reasonMessage
      ? `AI璇勪及涓嶅彲鐢紝宸插洖閫€瑙勫垯璇勫垎锛?{reasonMessage}`
      : 'AI璇勪及涓嶅彲鐢紝宸插洖閫€瑙勫垯璇勫垎銆?
  }
}

const resolveAssessment = (parsed: LLMRawResponse): ShotQualityAssessment => {
  const checks = normalizeChecks(parsed.checks)
  const weighted = weightedScore(checks)
  const score = toSafeScore(parsed.score, weighted)
  const grade = isGrade(parsed.grade) ? parsed.grade : resolveGrade(score)
  const summary =
    truncateText(parsed.summary, 260) || buildSummary(checks, grade)

  return {
    version: QUALITY_SCHEMA_VERSION,
    score,
    grade,
    generatedAt: Date.now(),
    checks,
    summary
  }
}

export const assessShotQualityWithLLM = async (
  shot: Shot,
  scriptData?: ScriptData | null,
  options?: LLMQualityAssessmentOptions
): Promise<ShotQualityAssessment> => {
  const activeChatModel = getActiveChatModel() as any
  const model =
    options?.model ||
    activeChatModel?.id ||
    activeChatModel?.apiModel ||
    'gpt-5.2'

  try {
    const prompt = buildPrompt(shot, scriptData)
    const responseText = await retryOperation(
      () =>
        chatCompletion(
          prompt,
          model,
          options?.temperature ?? 0.2,
          options?.maxTokens ?? 4096,
          'json_object',
          options?.timeoutMs ?? 120000
        ),
      options?.retries ?? 2,
      1500
    )

    const parsed = safeJsonParse(responseText)
    return resolveAssessment(parsed)
  } catch (error: any) {
    console.warn('[quality-v2] LLM scoring failed, fallback to V1.', error)
    return fallbackAssessment(shot, scriptData, error?.message)
  }
}

import { RenderLog } from '../types'

/**
 * Render Log Service
 * Manages API call logging for tracking generation history, costs, and debugging
 */

// Type for log creation callback - used to save logs to project state
type LogCallback = (log: RenderLog) => void

let logCallback: LogCallback | null = null

/**
 * Set the callback function that will be called when a new log is created
 * This callback should save the log to the project state
 */
export const setLogCallback = (callback: LogCallback) => {
  logCallback = callback
}

/**
 * Clear the log callback
 */
export const clearLogCallback = () => {
  logCallback = null
}

/**
 * Add a render log entry
 * Records an API call with all relevant metadata
 */
export const addRenderLog = (
  log: Omit<RenderLog, 'id' | 'timestamp'>
): void => {
  const fullLog: RenderLog = {
    ...log,
    id: `log-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
    timestamp: Date.now()
  }

  if (logCallback) {
    logCallback(fullLog)
  } else {
    console.warn('[RenderLog] No callback set - log not saved:', fullLog)
  }
}

/**
 * Helper to wrap an API operation with automatic logging
 * Captures timing, success/failure, and token usage
 */
export const withLogging = async <T>(
  operation: () => Promise<T>,
  logInfo: {
    type: RenderLog['type']
    resourceId: string
    resourceName: string
    model: string
    prompt?: string
  }
): Promise<T> => {
  const startTime = Date.now()

  try {
    const result = await operation()
    const duration = Date.now() - startTime

    addRenderLog({
      ...logInfo,
      status: 'success',
      duration
    })

    return result
  } catch (error: any) {
    const duration = Date.now() - startTime

    addRenderLog({
      ...logInfo,
      status: 'failed',
      error: error.message || String(error),
      duration
    })

    throw error
  }
}

/**
 * Helper to log with token information
 * Use this when you have token usage data from API response
 */
export const addRenderLogWithTokens = (
  logInfo: Omit<RenderLog, 'id' | 'timestamp'> & {
    inputTokens?: number
    outputTokens?: number
    totalTokens?: number
  }
): void => {
  addRenderLog(logInfo)
}
